export interface WorkDay {
  date: string; // ISO string YYYY-MM-DD
  hours: number; // Regular hours
  overtime50: number; // Overtime 50%
  overtime100: number; // Overtime 100%
  homeHours: number;
  isAbsent: boolean;
  isPaidAbsence?: boolean; // New: If absent, is it paid?
  isHoliday: boolean; // New: Holiday flag
  isVacation?: boolean; // New: Vacation flag
  note: string;
  startTime?: string; // Format "HH:mm"
  endTime?: string;   // Format "HH:mm"
}

export interface AppSettings {
  userName: string; // New field for the report header
  hourlyRate: number; // Defines the DEFAULT rate for new/future periods
  startDate: string; // Format YYYY-MM. Replaces seniorityYears
  seniorityPercentPerYear: number; // e.g., 1 for 1%
  nonRemunerativePercent: number; // e.g., 8 for 8%

  // Advance / Loan Tracking
  hasAdvance: boolean;
  advanceTotalAmount: number;
  advanceTotalInstallments: number;
  advanceStartPeriod: string; // Stores the PeriodID (YYYY-MM-Qx) when loan started
}

export interface PeriodState {
  id: string; // Format: YYYY-MM-Q1 or YYYY-MM-Q2
  isPaid: boolean;
  hourlyRate?: number; // Specific rate for this period
  nonRemunerativePercent?: number; // Snapshot for this period
  seniorityPercentPerYear?: number; // Snapshot for this period
}

export interface PeriodSummary {
  totalRegularHours: number;
  totalOvertime50: number;
  totalOvertime100: number;
  totalHomeHours: number;

  subtotalAmount: number; // Includes Regular, OT50, OT100, Home

  holidayItemCount: number; // How many holidays in period
  holidayAmount: number; // Amount paid for holidays (separate from worked hours)

  paidAbsenceCount: number; // New
  paidAbsenceAmount: number; // New

  vacationDays: number; // New
  vacationAmount: number; // New

  seniorityYears: number; // Calculated dynamically
  seniorityAmount: number;
  nonRemunerativeAmount: number;
  advanceDeduction: number;
  currentInstallmentNumber: number; // Calculated for this period

  grandTotal: number;

  appliedHourlyRate: number; // Information only
  appliedNonRemunerative: number; // Information only
}

// Default settings based on the screenshot analysis
export const DEFAULT_SETTINGS: AppSettings = {
  userName: 'Tu Nombre',
  hourlyRate: 6468,
  startDate: '2020-01', // Default start date
  seniorityPercentPerYear: 1,
  nonRemunerativePercent: 8,

  hasAdvance: false,
  advanceTotalAmount: 0,
  advanceTotalInstallments: 1,
  advanceStartPeriod: '',
};

import React, { useRef } from 'react';
import { X, Save, DollarSign, Briefcase, Percent, CreditCard, AlertCircle, Download, Upload, Calendar } from 'lucide-react';
import { AppSettings } from '../types';
import { db } from '../db';
import { getPeriodValue, getPeriodIdFromValue } from '../constants';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  settings: AppSettings;
  currentPeriodRate: number;
  currentPeriodId: string;
  onSave: (newSettings: AppSettings, periodRate: number, periodNonRem?: number, periodSeniority?: number) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  settings,
  currentPeriodRate,
  currentPeriodId,
  onSave,
}) => {
  const [localSettings, setLocalSettings] = React.useState<AppSettings>(settings);
  const [localPeriodRate, setLocalPeriodRate] = React.useState<number>(currentPeriodRate);
  const [calculatedCurrentInstallment, setCalculatedCurrentInstallment] = React.useState<number>(1);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reset local state when modal opens
  React.useEffect(() => {
    if (isOpen) {
      setLocalSettings(settings);
      setLocalPeriodRate(currentPeriodRate);

      // Calculate current installment based on start period and current period
      if (settings.advanceStartPeriod && currentPeriodId) {
          const currentVal = getPeriodValue(currentPeriodId);
          const startVal = getPeriodValue(settings.advanceStartPeriod);
          const diff = currentVal - startVal;
          // If diff is negative (start is in future), installment is negative (handled gracefully by input usually)
          // We default to 1 if invalid
          setCalculatedCurrentInstallment(diff + 1);
      } else {
          setCalculatedCurrentInstallment(1);
      }
    }
  }, [isOpen, settings, currentPeriodRate, currentPeriodId]);

  if (!isOpen) return null;

  const handleChange = (key: keyof AppSettings, value: any) => {
    let finalValue = value;
    if (key !== 'startDate' && typeof value === 'string') {
        finalValue = parseFloat(value) || 0;
    }
    setLocalSettings(prev => ({ ...prev, [key]: finalValue }));
  };

  const handleRateChange = (value: string) => {
      setLocalPeriodRate(parseFloat(value) || 0);
      // Also update global default to match user expectation of "Updating the rate"
      handleChange('hourlyRate', value);
  };

  const handleInstallmentChange = (valStr: string) => {
      const val = parseInt(valStr) || 1;
      setCalculatedCurrentInstallment(val);

      // Back-calculate the start period
      // Start = Current - (Installment - 1)
      const currentVal = getPeriodValue(currentPeriodId);
      const startVal = currentVal - (val - 1);
      const startPeriodId = getPeriodIdFromValue(startVal);

      setLocalSettings(prev => ({ ...prev, advanceStartPeriod: startPeriodId }));
  };

  const handleSave = () => {
    // Pass specific values to be locked for this period
    onSave(
        localSettings, 
        localPeriodRate, 
        localSettings.nonRemunerativePercent, 
        localSettings.seniorityPercentPerYear
    );
    onClose();
  };

  // Calculate estimated deduction for preview
  const advanceDeduction = localSettings.hasAdvance && localSettings.advanceTotalInstallments > 0
    ? localSettings.advanceTotalAmount / localSettings.advanceTotalInstallments
    : 0;

  const handleBackup = async () => {
    try {
        const [entries, periodStates] = await Promise.all([
            db.getAllEntries(),
            db.getAllPeriodStates()
        ]);

        const exportData = {
            settings: localSettings,
            entries: entries,
            periodStates: periodStates,
            exportDate: new Date().toISOString()
        };

        const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `liquidacion_pro_backup_${new Date().toISOString().split('T')[0]}.json`;
        a.click();
        URL.revokeObjectURL(url);
    } catch (e) {
        alert('Error generando backup');
        console.error(e);
    }
  };

  const handleRestoreClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      try {
          const text = await file.text();
          const data = JSON.parse(text);

          if (!data.entries || !data.settings) {
              throw new Error("Formato de archivo inválido");
          }

          if (confirm("¿Estás seguro? Esto sobrescribirá tus datos actuales con los del archivo de respaldo.")) {
              await db.importData(data);
              window.location.reload(); // Reload to refresh app state
          }
      } catch (err) {
          alert('Error al restaurar: Archivo inválido');
          console.error(err);
      }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-slate-900 border border-slate-700 rounded-xl shadow-2xl w-full max-w-md animate-in fade-in zoom-in duration-200 flex flex-col max-h-[85vh]">
        {/* Header (Fixed) */}
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-850 rounded-t-xl shrink-0">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Briefcase size={20} className="text-emerald-500" />
            Configuración
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Scrollable Content */}
        <div className="p-6 space-y-6 overflow-y-auto flex-1">

          {/* Section: General */}
          <div className="space-y-4">
            <h3 className="text-xs font-semibold uppercase text-slate-500 tracking-wider">General</h3>

            {/* Hourly Rate */}
            <div className="space-y-2 bg-emerald-900/10 p-3 rounded-lg border border-emerald-500/20">
              <label className="text-sm font-medium text-emerald-400 flex items-center justify-between">
                Valor de Hora (Esta Quincena)
              </label>
              <div className="relative">
                <DollarSign size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-emerald-500" />
                <input
                  type="number"
                  value={localPeriodRate}
                  onChange={(e) => handleRateChange(e.target.value)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 pl-9 pr-4 text-white focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all font-bold"
                />
              </div>
              <p className="text-[10px] text-slate-500">
                Este valor se guardará específicamente para la quincena actual.
              </p>
            </div>

            {/* Seniority Calculation */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">Fecha Ingreso</label>
                <div className="relative">
                    <Calendar size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                    <input
                    type="month"
                    value={localSettings.startDate || '2020-01'}
                    onChange={(e) => handleChange('startDate', e.target.value)}
                    className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 pl-8 pr-2 text-white focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all text-sm"
                    />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">% por Año</label>
                <div className="relative">
                   <Percent size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500" />
                  <input
                    type="number"
                    value={localSettings.seniorityPercentPerYear}
                    onChange={(e) => handleChange('seniorityPercentPerYear', e.target.value)}
                    className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 pl-4 pr-8 text-white focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
                  />
                </div>
              </div>
            </div>

            {/* Non Remunerative */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-400">No Remunerativo (%)</label>
              <div className="relative">
                <Percent size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500" />
                <input
                  type="number"
                  value={localSettings.nonRemunerativePercent}
                  onChange={(e) => handleChange('nonRemunerativePercent', e.target.value)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 pl-4 pr-9 text-white focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
                />
              </div>
              <p className="text-[10px] text-slate-500">
                El cambio aplicará desde esta quincena en adelante, manteniendo el historial de las anteriores.
              </p>
            </div>
          </div>

          <div className="h-px bg-slate-800" />

          {/* Section: Advances */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
               <h3 className="text-xs font-semibold uppercase text-slate-500 tracking-wider flex items-center gap-2">
                 <CreditCard size={14} /> Adelantos / Préstamos
               </h3>
               <label className="relative inline-flex items-center cursor-pointer">
                  <input 
                    type="checkbox" 
                    checked={localSettings.hasAdvance} 
                    onChange={(e) => handleChange('hasAdvance', e.target.checked)}
                    className="sr-only peer" 
                  />
                  <div className="w-9 h-5 bg-slate-700 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-emerald-600"></div>
                </label>
            </div>

            {localSettings.hasAdvance && (
              <div className="bg-slate-950/50 p-4 rounded-lg border border-slate-800 space-y-4 animate-in slide-in-from-top-2 duration-200">
                 <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-400">Monto Total del Adelanto</label>
                    <div className="relative">
                      <DollarSign size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                      <input
                        type="number"
                        value={localSettings.advanceTotalAmount}
                        onChange={(e) => handleChange('advanceTotalAmount', e.target.value)}
                        className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 pl-9 pr-4 text-white focus:ring-2 focus:ring-emerald-500 outline-none"
                        placeholder="0.00"
                      />
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-400">Cant. Cuotas</label>
                        <input
                          type="number"
                          min="1"
                          value={localSettings.advanceTotalInstallments}
                          onChange={(e) => handleChange('advanceTotalInstallments', e.target.value)}
                          className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 px-4 text-white focus:ring-2 focus:ring-emerald-500 outline-none"
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-400">Cuota Actual</label>
                        <input
                          type="number"
                          value={calculatedCurrentInstallment}
                          onChange={(e) => handleInstallmentChange(e.target.value)}
                          className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 px-4 text-white focus:ring-2 focus:ring-emerald-500 outline-none"
                        />
                    </div>
                 </div>

                 <div className="pt-2 border-t border-slate-800 flex items-start gap-2 text-xs text-slate-400">
                    <AlertCircle size={14} className="text-emerald-500 mt-0.5 shrink-0" />
                    <p>
                      Se descontarán 
                      <strong className="text-white mx-1">
                        ${new Intl.NumberFormat('es-AR').format(advanceDeduction)}
                      </strong>
                      en esta liquidación (Cuota {calculatedCurrentInstallment}/{localSettings.advanceTotalInstallments}).
                    </p>
                 </div>
              </div>
            )}
          </div>

          <div className="h-px bg-slate-800" />

          {/* Backup / Restore */}
           <div className="space-y-3">
             <h3 className="text-xs font-semibold uppercase text-slate-500 tracking-wider">Datos y Seguridad</h3>
             <div className="flex gap-3">
                <button 
                    onClick={handleBackup}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-lg text-sm transition-colors border border-slate-700"
                >
                    <Download size={16} /> Backup
                </button>
                <button 
                    onClick={handleRestoreClick}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-lg text-sm transition-colors border border-slate-700"
                >
                    <Upload size={16} /> Restaurar
                </button>
                <input 
                    type="file" 
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    accept=".json"
                    className="hidden"
                />
             </div>
             <p className="text-[10px] text-slate-500 text-center">
                Descarga un archivo .json para guardar tus datos o restáuralo en otro dispositivo.
             </p>
           </div>

        </div>

        {/* Footer (Fixed) */}
        <div className="p-4 border-t border-slate-800 bg-slate-850 flex justify-end gap-3 rounded-b-xl shrink-0">
          <button 
            onClick={onClose}
            className="px-4 py-2 rounded-lg text-slate-300 hover:text-white hover:bg-slate-800 transition-colors font-medium text-sm"
          >
            Cancelar
          </button>
          <button 
            onClick={handleSave}
            className="px-4 py-2 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-900/20 transition-all font-medium text-sm flex items-center gap-2"
          >
            <Save size={16} />
            Guardar Cambios
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  WorkDay, 
  AppSettings, 
  DEFAULT_SETTINGS, 
  PeriodSummary,
  PeriodState
} from './types';
import { 
  DAYS_OF_WEEK,
  MONTHS,
  formatCurrency,
  getPeriodValue
} from './constants';
import { PeriodSelector } from './components/PeriodSelector';
import { SettingsModal } from './components/SettingsModal';
import { SummaryPanel } from './components/SummaryPanel';
import { VacationModal } from './components/VacationModal';
import { Login } from './components/Login'; // New Component
import { auth } from './firebase'; // Auth instance
import { onAuthStateChanged, signOut, User as FirebaseUser } from 'firebase/auth'; // Auth methods

import { Settings as SettingsIcon, Database, Laptop, Clock, Loader2, CalendarOff, AlertTriangle, X, UserX, CheckCircle2, Palmtree, DollarSign, Image as ImageIcon, User, LogOut } from 'lucide-react';
import { db } from './db';
import html2canvas from 'html2canvas';

// Generate time options every 30 minutes (00:00, 00:30, ..., 23:30)
const TIME_OPTIONS = Array.from({ length: 48 }, (_, i) => {
  const h = Math.floor(i / 2);
  const m = i % 2 === 0 ? '00' : '30';
  return `${String(h).padStart(2, '0')}:${m}`;
});

function App() {
  // --- Auth State ---
  const [user, setUser] = useState<FirebaseUser | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  // --- App State ---
  const [entries, setEntries] = useState<Record<string, WorkDay>>({});
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [periodStates, setPeriodStates] = useState<Record<string, PeriodState>>({}); // Cache all period states

  // Auto-detect current date and quincena
  const [selectedDate, setSelectedDate] = useState(() => {
    const now = new Date();
    return new Date(now.getFullYear(), now.getMonth(), 1);
  });

  const [quincena, setQuincena] = useState<1 | 2>(() => {
    return new Date().getDate() <= 15 ? 1 : 2;
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isVacationModalOpen, setIsVacationModalOpen] = useState(false);
  const [dbStatus, setDbStatus] = useState<'loading' | 'ready' | 'saving'>('loading');
  const [showHomeColumn, setShowHomeColumn] = useState(false);
  const [showTimeCalculator, setShowTimeCalculator] = useState(false);
  const [exportStatus, setExportStatus] = useState<'idle' | 'loading' | 'done'>('idle');

  // Mobile Calendar State
  const [mobileSelectedDate, setMobileSelectedDate] = useState<string | null>(null);

  const reportRef = useRef<HTMLDivElement>(null);

  // --- Auth Effect ---
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // --- Load Data Effect (Only when user is logged in) ---
  useEffect(() => {
    if (!user) return;

    const loadData = async () => {
      setDbStatus('loading');
      try {
        const [storedEntries, storedSettings, storedPeriodStates] = await Promise.all([
          db.getAllEntries(),
          db.getSettings(),
          db.getAllPeriodStates()
        ]);

        let initialEntries = storedEntries || {};
        setEntries(initialEntries);

        if (storedSettings) {
            setSettings({...DEFAULT_SETTINGS, ...storedSettings});
        } 

        const statesMap: Record<string, PeriodState> = {};
        storedPeriodStates.forEach(ps => {
            statesMap[ps.id] = ps;
        });
        setPeriodStates(statesMap);

        setDbStatus('ready');
      } catch (e) {
        console.error("Failed to load data from DB", e);
        setDbStatus('ready');
      }
    };
    loadData();
  }, [user]);

  // Logic Helpers
  const currentPeriodId = useMemo(() => {
      return `${selectedDate.getFullYear()}-${selectedDate.getMonth() + 1}-Q${quincena}`;
  }, [selectedDate, quincena]);

  const isPeriodPaid = useMemo(() => {
      return periodStates[currentPeriodId]?.isPaid || false;
  }, [periodStates, currentPeriodId]);

  // Calculate the Effective Hourly Rate for the CURRENT view
  const currentHourlyRate = useMemo(() => {
      // If this period has a specific rate saved, use it.
      if (periodStates[currentPeriodId]?.hourlyRate) {
          return periodStates[currentPeriodId].hourlyRate!;
      }
      // Otherwise fall back to the global setting
      return settings.hourlyRate;
  }, [periodStates, currentPeriodId, settings.hourlyRate]);


  // --- Handlers ---

  const handleLogout = () => {
    signOut(auth);
  };

  const handleTogglePeriodPaid = async () => {
      const newState = !isPeriodPaid;

      // When marking as paid (or toggling), we should snapshot critical values to ensure history is preserved
      // even if global settings change later.
      const updatedState: PeriodState = { 
          ...periodStates[currentPeriodId], 
          id: currentPeriodId, 
          isPaid: newState,
          // Snapshot values if they don't exist yet
          hourlyRate: periodStates[currentPeriodId]?.hourlyRate || settings.hourlyRate,
          nonRemunerativePercent: periodStates[currentPeriodId]?.nonRemunerativePercent ?? settings.nonRemunerativePercent,
          seniorityPercentPerYear: periodStates[currentPeriodId]?.seniorityPercentPerYear ?? settings.seniorityPercentPerYear
      };

      setPeriodStates(prev => ({ ...prev, [currentPeriodId]: updatedState }));
      await db.savePeriodState(updatedState);
  };

  // Updated: Handle Saving Settings including Period Rate
  const handleSettingsSave = async (newSettings: AppSettings, periodSpecificRate?: number, periodNonRem?: number, periodSeniority?: number) => {
    setSettings(newSettings);
    await db.saveSettings(newSettings);

    // If we are saving settings, we update the Global Settings (for defaults)
    // AND we explicitly update the *Current Period's* snapshot. 
    // This allows the user to change "Non Remunerative" now and have it stick for this period 
    // and future ones (via global), but not retroactive to UNTOUCHED past periods (which use their own snapshots).

    // We update the current period state with the new values to "Lock them in" for this view.
    const updatedState: PeriodState = {
        ...periodStates[currentPeriodId],
        id: currentPeriodId,
        isPaid: periodStates[currentPeriodId]?.isPaid || false,
        hourlyRate: periodSpecificRate !== undefined ? periodSpecificRate : (periodStates[currentPeriodId]?.hourlyRate || newSettings.hourlyRate),
        nonRemunerativePercent: periodNonRem !== undefined ? periodNonRem : (periodStates[currentPeriodId]?.nonRemunerativePercent || newSettings.nonRemunerativePercent),
        seniorityPercentPerYear: periodSeniority !== undefined ? periodSeniority : (periodStates[currentPeriodId]?.seniorityPercentPerYear || newSettings.seniorityPercentPerYear)
    };

    setPeriodStates(prev => ({ ...prev, [currentPeriodId]: updatedState }));
    await db.savePeriodState(updatedState);
  };

  const handleSettingQuickUpdate = async (key: keyof AppSettings, value: any) => {
      const newSettings = { ...settings, [key]: value };
      setSettings(newSettings);
      // Debounce or just save (IndexedDB is fast enough for this usage)
      await db.saveSettings(newSettings);
  };

  const handleVacationSubmit = async (startStr: string, endStr: string, includeWeekends: boolean) => {
      const start = new Date(startStr);
      start.setHours(12, 0, 0, 0); // Avoid timezone edge cases
      const end = new Date(endStr);
      end.setHours(12, 0, 0, 0);

      setDbStatus('saving');

      const newEntries = { ...entries };

      // Iterate from start to end
      for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
          const dayOfWeek = d.getDay();
          const isWeekend = dayOfWeek === 0 || dayOfWeek === 6; // 0 Sun, 6 Sat

          if (isWeekend && !includeWeekends) {
              continue; // Skip updating weekends if not requested
          }

          const dateStr = d.toISOString().split('T')[0];

          // Create or update entry
          const existing = newEntries[dateStr] || getEntry(dateStr);

          const updated: WorkDay = {
              ...existing,
              date: dateStr,
              isVacation: true,
              // Reset other flags and values
              isAbsent: false,
              isHoliday: false,
              isPaidAbsence: false,
              hours: 0,
              homeHours: 0,
              overtime50: 0,
              overtime100: 0,
              note: existing.note ? existing.note : 'Vacaciones'
          };

          newEntries[dateStr] = updated;
          await db.saveEntry(updated);
      }

      setEntries(newEntries);
      setTimeout(() => setDbStatus('ready'), 500);
  };

  const daysInPeriod = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const days: Date[] = [];

    const lastDayOfMonth = new Date(year, month + 1, 0).getDate();

    const startDay = quincena === 1 ? 1 : 16;
    const endDay = quincena === 1 ? 15 : lastDayOfMonth;

    for (let d = startDay; d <= endDay; d++) {
      const date = new Date(year, month, d);
      const dayOfWeek = date.getDay(); // 0 is Sunday, 6 is Saturday

      if (dayOfWeek !== 0 && dayOfWeek !== 6) {
        days.push(date);
      }
    }
    return days;
  }, [selectedDate, quincena]);

  const getEntry = (dateStr: string): WorkDay => {
    return entries[dateStr] || {
      date: dateStr,
      hours: 0,
      overtime50: 0,
      overtime100: 0,
      homeHours: 0,
      isAbsent: false,
      isPaidAbsence: false,
      isHoliday: false,
      isVacation: false,
      note: '',
      startTime: '08:00',
      endTime: ''
    };
  };

  const calculateTimeDiff = (start: string, end: string): number => {
    if (!start || !end) return 0;
    const [startH, startM] = start.split(':').map(Number);
    const [endH, endM] = end.split(':').map(Number);
    const startDate = new Date(2000, 0, 1, startH, startM);
    const endDate = new Date(2000, 0, 1, endH, endM);
    let diffMs = endDate.getTime() - startDate.getTime();
    if (diffMs < 0) {
        diffMs += 24 * 60 * 60 * 1000;
    }
    const hours = diffMs / (1000 * 60 * 60);
    return Math.round(hours * 100) / 100;
  };

  const calculateUpdatedEntry = (currentEntry: WorkDay, field: keyof WorkDay, value: any): WorkDay => {
    let updatedEntry = { ...currentEntry, [field]: value };

    // Logic exclusivity: Absent vs Holiday vs Vacation
    if (field === 'isAbsent') {
        if (value === true) {
            updatedEntry = { 
                ...updatedEntry, 
                isAbsent: true, 
                isHoliday: false, 
                isVacation: false, // exclusive
                hours: 0, 
                homeHours: 0, 
                overtime50: 0, 
                overtime100: 0,
                isPaidAbsence: currentEntry.isPaidAbsence 
            };
        }
    }

    if (field === 'isHoliday') {
        if (value === true) {
            updatedEntry = { ...updatedEntry, isHoliday: true, isAbsent: false, isVacation: false };
        }
    }

    if (field === 'isVacation') {
        if (value === true) {
            updatedEntry = { 
                ...updatedEntry, 
                isVacation: true, 
                isHoliday: false, 
                isAbsent: false,
                hours: 0, 
                homeHours: 0, 
                overtime50: 0, 
                overtime100: 0
            };
        }
    }

    // If hours are added, reset exclusives
    if ((field === 'hours' || field === 'homeHours' || field === 'overtime50' || field === 'overtime100') && value > 0) {
        updatedEntry = { ...updatedEntry, [field]: value, isAbsent: false, isVacation: false };
    }

    if (field === 'startTime' || field === 'endTime') {
        const start = field === 'startTime' ? value : currentEntry.startTime;
        const end = field === 'endTime' ? value : currentEntry.endTime;
        if (start && end) {
            const calcHours = calculateTimeDiff(start, end);
            if (calcHours > 0) {
                updatedEntry = { ...updatedEntry, hours: calcHours, isAbsent: false, isVacation: false };
            }
        }
    }

    return updatedEntry;
  };

  const handleLocalChange = (dateStr: string, field: keyof WorkDay, value: any) => {
    setEntries(prev => {
      const currentEntry = prev[dateStr] || getEntry(dateStr);
      const updatedEntry = calculateUpdatedEntry(currentEntry, field, value);
      return { ...prev, [dateStr]: updatedEntry };
    });
  };

  const handlePersist = async (dateStr: string) => {
    const entryToSave = entries[dateStr];
    if (!entryToSave) return;

    setDbStatus('saving');
    try {
      await db.saveEntry(entryToSave);
      setTimeout(() => setDbStatus('ready'), 500);
    } catch (e) {
      console.error("Failed to save to DB", e);
      setDbStatus('ready');
    }
  };

  const handleImmediateChange = async (dateStr: string, field: keyof WorkDay, value: any) => {
    setEntries(prev => {
      const currentEntry = prev[dateStr] || getEntry(dateStr);
      const updatedEntry = calculateUpdatedEntry(currentEntry, field, value);
      return { ...prev, [dateStr]: updatedEntry };
    });
    setDbStatus('saving');
    try {
        const currentEntry = entries[dateStr] || getEntry(dateStr);
        const updatedEntry = calculateUpdatedEntry(currentEntry, field, value);
        await db.saveEntry(updatedEntry);
        setTimeout(() => setDbStatus('ready'), 500);
    } catch (e) {
        console.error(e);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.currentTarget.blur();
    }
  };

  // --- Period Summary Calculations ---
  const periodSummary: PeriodSummary = useMemo(() => {
    // 1. Resolve Rate: Period Specific vs Global
    const rate = currentHourlyRate;

    // 2. Resolve Non-Remunerative %: Period Specific vs Global
    const appliedNonRemunerative = periodStates[currentPeriodId]?.nonRemunerativePercent ?? settings.nonRemunerativePercent;

    // 3. Resolve Seniority %: Period Specific vs Global
    const appliedSeniorityPercent = periodStates[currentPeriodId]?.seniorityPercentPerYear ?? settings.seniorityPercentPerYear;

    let totalRegularHours = 0;
    let totalHomeHours = 0;
    let totalOvertime50 = 0;
    let totalOvertime100 = 0;
    let holidayItemCount = 0;
    let holidayAmount = 0;
    let paidAbsenceCount = 0;
    let paidAbsenceAmount = 0;
    let vacationDays = 0;
    let vacationAmount = 0;

    daysInPeriod.forEach(d => {
      const dateStr = d.toISOString().split('T')[0];
      const entry = entries[dateStr];
      if (entry) {
        totalRegularHours += (entry.hours || 0);
        totalHomeHours += (entry.homeHours || 0);
        totalOvertime50 += (entry.overtime50 || 0);
        totalOvertime100 += (entry.overtime100 || 0);

        if (entry.isHoliday) {
            holidayItemCount++;
            holidayAmount += (8 * rate);
        }

        if (entry.isAbsent && entry.isPaidAbsence) {
            paidAbsenceCount++;
            paidAbsenceAmount += (8 * rate);
        }

        if (entry.isVacation) {
            vacationDays++;
            vacationAmount += (8 * rate);
        }
      }
    });

    const regularAmount = totalRegularHours * rate;
    const homeAmount = totalHomeHours * rate;
    const ot50Amount = totalOvertime50 * rate * 1.5;
    const ot100Amount = totalOvertime100 * rate * 2;

    const subtotalAmount = regularAmount + homeAmount + ot50Amount + ot100Amount + holidayAmount + paidAbsenceAmount + vacationAmount;

    // 4. Calculate Seniority Years Dynamically based on Settings.StartDate vs SelectedDate
    let yearsOfSeniority = 0;
    if (settings.startDate) {
        const start = new Date(settings.startDate + '-01'); // Append day to YYYY-MM
        const current = new Date(selectedDate);

        if (!isNaN(start.getTime())) {
            let diffYears = current.getFullYear() - start.getFullYear();
            let diffMonths = current.getMonth() - start.getMonth();

            if (diffMonths < 0 || (diffMonths === 0 && current.getDate() < start.getDate())) {
                diffYears--;
            }
            yearsOfSeniority = Math.max(0, diffYears);
        }
    }

    const seniorityPercent = (yearsOfSeniority * appliedSeniorityPercent) / 100;
    const seniorityAmount = subtotalAmount * seniorityPercent;

    const nonRemunerativeAmount = subtotalAmount * (appliedNonRemunerative / 100);

    let advanceDeduction = 0;
    let currentInstallmentNumber = 0;

    if (settings.hasAdvance && settings.advanceTotalInstallments > 0 && settings.advanceStartPeriod) {
        const currentVal = getPeriodValue(currentPeriodId);
        const startVal = getPeriodValue(settings.advanceStartPeriod);
        const diff = currentVal - startVal;

        // Installment is 0-indexed diff + 1. i.e., if diff is 0 (same period), it's 1st installment.
        const installmentNum = diff + 1;

        if (installmentNum > 0 && installmentNum <= settings.advanceTotalInstallments) {
             advanceDeduction = settings.advanceTotalAmount / settings.advanceTotalInstallments;
             currentInstallmentNumber = installmentNum;
        }
    }

    const grandTotal = subtotalAmount + seniorityAmount + nonRemunerativeAmount - advanceDeduction;

    return {
      totalRegularHours,
      totalHomeHours,
      totalOvertime50,
      totalOvertime100,
      holidayItemCount,
      holidayAmount,
      paidAbsenceCount,
      paidAbsenceAmount,
      vacationDays,
      vacationAmount,
      subtotalAmount,
      seniorityYears: yearsOfSeniority,
      seniorityAmount,
      nonRemunerativeAmount,
      advanceDeduction,
      currentInstallmentNumber,
      grandTotal,
      appliedHourlyRate: rate,
      appliedNonRemunerative,
    };
  }, [daysInPeriod, entries, settings, currentHourlyRate, selectedDate, quincena, periodStates, currentPeriodId]);

  const dailyChartData = useMemo(() => {
    return daysInPeriod.map(d => {
      const dateStr = d.toISOString().split('T')[0];
      const entry = entries[dateStr];
      return {
        date: dateStr,
        hours: (entry?.hours || 0) + (entry?.homeHours || 0) + (entry?.overtime50 || 0) + (entry?.overtime100 || 0),
        isHoliday: !!entry?.isHoliday
      };
    });
  }, [daysInPeriod, entries]);

  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const firstDayOfWeek = new Date(year, month, 1).getDay();

    const days = [];
    for (let i = 0; i < firstDayOfWeek; i++) {
        days.push(null);
    }
    for (let i = 1; i <= daysInMonth; i++) {
        days.push(new Date(year, month, i));
    }
    return days;
  }, [selectedDate]);

  const handleExportImage = async () => {
      if (!reportRef.current) return;
      setExportStatus('loading');

      // Small delay to ensure React rendering (if any) catches up
      await new Promise(resolve => setTimeout(resolve, 100));

      try {
        const canvas = await html2canvas(reportRef.current, {
            backgroundColor: '#020617', // Force slate-950 background
            scale: 2, // Higher resolution
            logging: false,
            useCORS: true,
            ignoreElements: (element) => {
                return element.classList.contains('no-export');
            }
        });

        const image = canvas.toDataURL("image/png");
        const link = document.createElement('a');
        link.href = image;
        link.download = `Liquidacion_${selectedDate.getFullYear()}_${selectedDate.getMonth()+1}_Q${quincena}.png`;
        link.click();

        setExportStatus('done');
      } catch (error) {
        console.error("Export failed:", error);
        alert("Hubo un error al generar la imagen.");
        setExportStatus('idle');
      }

      setTimeout(() => setExportStatus('idle'), 2000);
  };

  // --- Conditional Rendering for Auth ---

  if (authLoading) {
      return (
          <div className="min-h-screen bg-slate-950 flex items-center justify-center">
              <Loader2 size={48} className="animate-spin text-emerald-500" />
          </div>
      );
  }

  if (!user) {
      return <Login />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 pb-20 font-sans">
      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30 no-print">
        <div className="max-w-6xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-3">
             {/* User Name Input - Synced with Firestore now */}
             <div className="flex items-center gap-2 bg-slate-800/50 p-1 pl-2 pr-3 rounded-full border border-slate-700 hover:border-slate-600 transition-colors">
                 <div className="w-6 h-6 bg-gradient-to-br from-slate-700 to-slate-800 rounded-full flex items-center justify-center text-slate-400">
                    <User size={14} />
                 </div>
                 <input 
                    type="text"
                    value={settings.userName}
                    onChange={(e) => handleSettingQuickUpdate('userName', e.target.value)}
                    placeholder="Tu Nombre"
                    className="bg-transparent border-none text-sm font-bold text-slate-200 focus:outline-none w-32 sm:w-40 placeholder-slate-600"
                 />
             </div>

            {dbStatus === 'loading' && (
               <span className="text-xs text-slate-500 flex items-center gap-1 ml-2">
                 <Loader2 size={12} className="animate-spin" />
               </span>
            )}
          </div>

          <div className="flex items-center gap-2">
             <button
                onClick={() => setIsVacationModalOpen(true)}
                className="p-1.5 text-slate-400 hover:text-purple-400 hover:bg-purple-900/20 rounded-full transition-colors"
                title="Agregar Vacaciones"
             >
                <Palmtree size={18} />
             </button>

             <button 
                onClick={handleExportImage}
                disabled={exportStatus === 'loading'}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-emerald-600/10 hover:bg-emerald-600/20 text-emerald-400 hover:text-emerald-300 transition-all text-xs font-medium border border-emerald-600/30"
             >
                {exportStatus === 'loading' ? <Loader2 size={14} className="animate-spin" /> : <ImageIcon size={14} />}
                <span className="hidden sm:inline">IMG</span>
             </button>

             <button 
                onClick={() => setIsSettingsOpen(true)}
                className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors"
            >
                <SettingsIcon size={18} />
            </button>

            <div className="w-px h-6 bg-slate-800 mx-1"></div>

            <button 
                onClick={handleLogout}
                className="p-1.5 text-slate-500 hover:text-red-400 hover:bg-red-900/20 rounded-full transition-colors"
                title="Cerrar Sesión"
            >
                <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-2 sm:px-4 py-6">

        <div className="no-print">
            <PeriodSelector 
            selectedDate={selectedDate}
            quincena={quincena}
            onDateChange={setSelectedDate}
            onQuincenaChange={setQuincena}
            />
        </div>

        {/* CAPTURE AREA */}
        <div ref={reportRef} className="bg-slate-950 p-0 sm:p-4 rounded-xl border border-transparent">

            {/* Header visible ONLY in export (or inside the capture area) */}
            <div className="mb-4 flex justify-between items-end border-b border-slate-800 pb-4 px-2">
                <div className="flex flex-col gap-1">
                     {/* Restored LOGO here */}
                     <div className="flex items-center gap-2">
                        <div className="w-7 h-7 bg-gradient-to-br from-emerald-500 to-emerald-700 rounded-md flex items-center justify-center shadow-lg shadow-emerald-900/50">
                            <span className="font-bold text-white text-base">S</span>
                        </div>
                        <h1 className="font-bold text-lg tracking-tight text-white">
                            SUM<span className="text-emerald-500">M</span>A
                        </h1>
                     </div>
                     {/* Static User Name Display */}
                     <div className="text-slate-400 font-medium text-sm ml-1">
                        {settings.userName}
                     </div>
                </div>
                <div className="text-right flex flex-col items-end">
                     <p className="text-emerald-400 font-mono font-bold text-lg leading-none mb-1">
                         {MONTHS[selectedDate.getMonth()]} {selectedDate.getFullYear()}
                     </p>
                     <p className="text-slate-400 text-sm uppercase tracking-wider leading-none">
                         {quincena}ª Quincena
                     </p>
                </div>
            </div>

            <SummaryPanel 
                summary={periodSummary} 
                settings={settings} 
                dailyData={dailyChartData}
                isPeriodPaid={isPeriodPaid}
                onTogglePaid={handleTogglePeriodPaid}
            />
        </div>
        {/* END CAPTURE AREA */}

        {/* Universal Calendar View - OUTSIDE CAPTURE */}
        <div className="mt-6 bg-slate-900 rounded-xl border border-slate-800 p-4 shadow-xl">
            <div className="flex items-center justify-between mb-4">
                <h2 className="font-semibold text-slate-200 flex items-center gap-2">
                    <Clock size={16} className="text-emerald-500" />
                    Calendario
                </h2>
                <span className="text-xs text-slate-500 uppercase">{MONTHS[selectedDate.getMonth()]}</span>
            </div>

            <div className="grid grid-cols-7 gap-2 mb-2">
                {DAYS_OF_WEEK.map(d => (
                    <div key={d} className="text-center text-[10px] text-slate-500 font-bold uppercase">
                        {d.charAt(0)}
                    </div>
                ))}
            </div>
            <div className="grid grid-cols-7 gap-2">
                {calendarDays.map((date, i) => {
                    if (!date) return <div key={`empty-${i}`} className="aspect-square" />;

                    const dateStr = date.toISOString().split('T')[0];
                    const entry = getEntry(dateStr);
                    const dayNum = date.getDate();
                    const dayOfWeek = date.getDay();

                    const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
                    const isCurrentQuincena = quincena === 1 ? dayNum <= 15 : dayNum > 15;
                    const isWorkingDay = !isWeekend && isCurrentQuincena;
                    const isToday = new Date().getDate() === dayNum && 
                                    new Date().getMonth() === date.getMonth() && 
                                    new Date().getFullYear() === date.getFullYear();

                    let bgClass = 'bg-transparent';
                    let textClass = 'text-slate-600';
                    let borderClass = 'border-transparent';
                    let shadowClass = '';

                    if (isWorkingDay) {
                            bgClass = 'bg-slate-800';
                            textClass = 'text-slate-200 font-medium';
                            borderClass = 'border-slate-700';
                            shadowClass = 'shadow-sm shadow-black/50';
                    } else if (isWeekend && isCurrentQuincena) {
                        textClass = 'text-slate-500';
                        bgClass = 'bg-slate-900/30';
                    }

                    if (entry.isHoliday) {
                        bgClass = 'bg-yellow-900/20';
                        textClass = 'text-yellow-500 font-bold';
                        borderClass = 'border-yellow-500/30';
                    } else if (entry.isAbsent) {
                        bgClass = 'bg-red-900/20';
                        textClass = 'text-red-400 font-bold';
                        borderClass = 'border-red-500/30';
                    } else if (entry.isVacation) {
                        bgClass = 'bg-purple-900/20';
                        textClass = 'text-purple-400 font-bold';
                        borderClass = 'border-purple-500/30';
                    }

                    if (dateStr === mobileSelectedDate) {
                        borderClass = 'border-emerald-500';
                        bgClass = 'bg-slate-800';
                        textClass = 'text-emerald-400';
                    }

                    if (isToday) {
                        borderClass = 'border-blue-400 shadow-[0_0_12px_rgba(96,165,250,0.3)]';
                        textClass = 'text-blue-300 font-bold';
                        bgClass = 'bg-blue-950';
                    }

                    const totalHours = (entry.hours || 0) + (entry.homeHours || 0) + (entry.overtime50 || 0) + (entry.overtime100 || 0);

                    return (
                        <button 
                            key={dateStr}
                            onClick={() => {
                                setMobileSelectedDate(dateStr);
                            }}
                            className={`aspect-square rounded-lg border ${borderClass} ${bgClass} ${shadowClass} flex flex-col items-center justify-center relative transition-all active:scale-95`}
                        >
                            <span className={`text-sm ${textClass}`}>{dayNum}</span>

                            {totalHours > 0 && (
                                <span className="text-[10px] font-mono font-medium text-emerald-400 mt-0.5">
                                    {totalHours}hs
                                </span>
                            )}

                            {entry.isAbsent && (
                                    <span className="text-[9px] font-bold text-red-400 mt-0.5 leading-none">
                                        AUS
                                    </span>
                            )}

                            {entry.isVacation && (
                                    <span className="text-[9px] font-bold text-purple-400 mt-0.5 leading-none">
                                        VAC
                                    </span>
                            )}

                            <div className="flex gap-0.5 mt-0.5">
                                {entry.homeHours > 0 && <div className="w-1 h-1 rounded-full bg-blue-500"></div>}
                                {entry.isHoliday && <div className="w-1 h-1 rounded-full bg-yellow-500"></div>}
                                {entry.isVacation && <div className="w-1 h-1 rounded-full bg-purple-500"></div>}
                                {entry.isAbsent && entry.isPaidAbsence && <div className="w-1 h-1 rounded-full bg-emerald-500"></div>}
                            </div>
                        </button>
                    );
                })}
            </div>
        </div>

        {/* Universal Modal for Editing */}
        {mobileSelectedDate && (
            <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
                <div 
                    className="bg-slate-900 w-full md:w-full md:max-w-md rounded-t-2xl md:rounded-2xl border border-slate-700 p-6 animate-in slide-in-from-bottom md:slide-in-from-bottom-10 duration-300 shadow-2xl"
                    onClick={(e) => e.stopPropagation()}
                >
                    <div className="flex justify-between items-center mb-6">
                            <div>
                            <h3 className="text-xl font-bold text-white flex items-center gap-2">
                                {new Date(mobileSelectedDate + 'T00:00:00').getDate()} de {MONTHS[new Date(mobileSelectedDate + 'T00:00:00').getMonth()]}
                            </h3>
                            <p className="text-sm text-slate-500 uppercase">
                                {DAYS_OF_WEEK[new Date(mobileSelectedDate + 'T00:00:00').getDay()]}
                            </p>
                            </div>
                            <button 
                            onClick={() => setMobileSelectedDate(null)}
                            className="p-2 bg-slate-800 rounded-full text-slate-400 hover:text-white"
                            >
                            <X size={20} />
                            </button>
                    </div>

                    {/* SPECIAL STATUS SECTION (Holiday / Absent / Vacation) */}
                    <div className="bg-slate-950/50 rounded-xl p-1 mb-6 grid grid-cols-3 gap-1">
                        {/* Holiday Toggle */}
                        <button
                            onClick={() => handleImmediateChange(mobileSelectedDate, 'isHoliday', !getEntry(mobileSelectedDate).isHoliday)}
                            className={`py-3 rounded-lg flex flex-col items-center justify-center gap-1 transition-all ${
                                getEntry(mobileSelectedDate).isHoliday 
                                ? 'bg-yellow-500/20 text-yellow-400 ring-1 ring-yellow-500 shadow-lg' 
                                : 'bg-transparent text-slate-500 hover:bg-slate-800 hover:text-slate-300'
                            }`}
                        >
                            {getEntry(mobileSelectedDate).isHoliday ? <CheckCircle2 size={18} /> : <CalendarOff size={18} />}
                            <span className="text-[10px] font-bold">FERIADO</span>
                        </button>

                        {/* Vacation Toggle */}
                        <button
                            onClick={() => handleImmediateChange(mobileSelectedDate, 'isVacation', !getEntry(mobileSelectedDate).isVacation)}
                            className={`py-3 rounded-lg flex flex-col items-center justify-center gap-1 transition-all ${
                                getEntry(mobileSelectedDate).isVacation 
                                ? 'bg-purple-500/20 text-purple-400 ring-1 ring-purple-500 shadow-lg' 
                                : 'bg-transparent text-slate-500 hover:bg-slate-800 hover:text-slate-300'
                            }`}
                        >
                            {getEntry(mobileSelectedDate).isVacation ? <Palmtree size={18} /> : <Palmtree size={18} className="opacity-50" />}
                            <span className="text-[10px] font-bold">VACACIONES</span>
                        </button>

                        {/* Absent Toggle */}
                        <button
                            onClick={() => handleImmediateChange(mobileSelectedDate, 'isAbsent', !getEntry(mobileSelectedDate).isAbsent)}
                            className={`py-3 rounded-lg flex flex-col items-center justify-center gap-1 transition-all ${
                                getEntry(mobileSelectedDate).isAbsent 
                                ? 'bg-red-500/20 text-red-400 ring-1 ring-red-500 shadow-lg' 
                                : 'bg-transparent text-slate-500 hover:bg-slate-800 hover:text-slate-300'
                            }`}
                        >
                            {getEntry(mobileSelectedDate).isAbsent ? <UserX size={18} /> : <UserX size={18} className="opacity-50" />}
                            <span className="text-[10px] font-bold">AUSENTE</span>
                        </button>
                    </div>

