export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('es-AR', {
    style: 'currency',
    currency: 'ARS',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
};

export const getPeriodValue = (periodId: string) => {
  if (!periodId) return 0;
  const [y, m] = periodId.split('-');
  return parseInt(y) * 12 + (parseInt(m) - 1);
};

export const getPeriodIdFromValue = (value: number) => {
  const y = Math.floor(value / 12);
  const m = (value % 12) + 1;
  return `${y}-${String(m).padStart(2, '0')}`;
};

import React from 'react';
import { ChevronLeft, ChevronRight, Calendar } from 'lucide-react';
import { MONTHS } from '../constants';

interface PeriodSelectorProps {
  selectedDate: Date;
  onDateChange: (date: Date) => void;
}

export const PeriodSelector: React.FC<PeriodSelectorProps> = ({
  selectedDate,
  onDateChange,
}) => {
  const handlePrevMonth = () => {
    const newDate = new Date(selectedDate);
    newDate.setMonth(newDate.getMonth() - 1);
    onDateChange(newDate);
  };

  const handleNextMonth = () => {
    const newDate = new Date(selectedDate);
    newDate.setMonth(newDate.getMonth() + 1);
    onDateChange(newDate);
  };

  return (
    <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg mb-6 flex items-center justify-between">
      <div className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg w-full">
        <button 
          onClick={handlePrevMonth}
          className="p-2 hover:bg-slate-700 rounded-md text-slate-400 hover:text-white transition-colors"
        >
          <ChevronLeft size={20} />
        </button>
        <div className="flex-1 flex items-center gap-2 px-4 justify-center font-semibold text-lg">
          <Calendar size={18} className="text-emerald-500" />
          <span className="capitalize">{MONTHS[selectedDate.getMonth()]} {selectedDate.getFullYear()}</span>
        </div>
        <button 
          onClick={handleNextMonth}
          className="p-2 hover:bg-slate-700 rounded-md text-slate-400 hover:text-white transition-colors"
        >
          <ChevronRight size={20} />
        </button>
      </div>
    </div>
  );
};

