              <div className="relative">
                <DollarSign size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-emerald-500" />
                <input
                  type="number"
                  value={localPeriodRate}
                  onChange={(e) => setLocalPeriodRate(parseFloat(e.target.value) || 0)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 pl-9 text-white outline-none font-bold"
                />
              </div>
            </div>

            <div className="space-y-2 bg-blue-900/10 p-3 rounded-lg border border-blue-500/20">
              <label className="text-sm font-medium text-blue-400 flex items-center justify-between">
                Objetivo Diario de Tiempo
                <span className="text-xs font-mono">{formatCurrency(localSettings.dailyTargetHours * localPeriodRate)}</span>
              </label>
              <div className="relative">
                <Target size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-blue-500" />
                <input
                  type="number"
                  value={localSettings.dailyTargetHours}
                  onChange={(e) => handleChange('dailyTargetHours', e.target.value)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 pl-9 text-white outline-none font-bold"
                />
              </div>
              <p className="text-[10px] text-slate-500">Horas que planeas trabajar por día para alcanzar tu meta económica.</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">Fecha Ingreso</label>
                <input
                  type="month"
                  value={localSettings.startDate}
                  onChange={(e) => handleChange('startDate', e.target.value)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 px-2 text-white text-sm"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-400">% No Rem.</label>
                <input
                  type="number"
                  value={localSettings.nonRemunerativePercent}
                  onChange={(e) => handleChange('nonRemunerativePercent', e.target.value)}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg py-2 px-4 text-white"
                />
