  };

  const handleImmediateChange = async (dateStr: string, field: keyof WorkDay, value: any) => {
    const entry = getEntry(dateStr);
    const updatedEntry = { ...entry, [field]: value };
    setEntries(prev => ({ ...prev, [dateStr]: updatedEntry }));
    await db.saveEntry(updatedEntry);
  };

  const periodSummary = useMemo(() => {
    const rate = currentHourlyRate;
    const appliedNonRem = periodStates[currentPeriodId]?.nonRemunerativePercent ?? settings.nonRemunerativePercent;
    let stats = { reg: 0, home: 0, hol: 0, holAmt: 0, abs: 0, absAmt: 0, vac: 0, vacAmt: 0 };

    daysInPeriod.forEach(d => {
      const entry = entries[d.toISOString().split('T')[0]];
      if (entry) {
        stats.reg += (entry.hours || 0);
        stats.home += (entry.homeHours || 0);
        if (entry.isHoliday) { stats.hol++; stats.holAmt += (8 * rate); }
        if (entry.isAbsent && entry.isPaidAbsence) { stats.abs++; stats.absAmt += (8 * rate); }
        if (entry.isVacation) { stats.vac++; stats.vacAmt += (8 * rate); }
      }
    });

    const subtotal = (stats.reg + stats.home) * rate + stats.holAmt + stats.absAmt + stats.vacAmt;
    const seniorityYears = settings.startDate ? Math.max(0, selectedDate.getFullYear() - new Date(settings.startDate).getFullYear()) : 0;
    const seniorityAmt = subtotal * (seniorityYears * settings.seniorityPercentPerYear / 100);
    const nonRemAmt = subtotal * (appliedNonRem / 100);

    return {
      ...stats, totalRegularHours: stats.reg, totalHomeHours: stats.home, holidayItemCount: stats.hol, holidayAmount: stats.holAmt,
      paidAbsenceCount: stats.abs, paidAbsenceAmount: stats.absAmt, vacationDays: stats.vac, vacationAmount: stats.vacAmt,
      subtotalAmount: subtotal, seniorityYears, seniorityAmount: seniorityAmt, nonRemunerativeAmount: nonRemAmt,
      grandTotal: subtotal + seniorityAmt + nonRemAmt, appliedHourlyRate: rate, appliedNonRemunerative: appliedNonRem,
      totalOvertime50: 0, totalOvertime100: 0, advanceDeduction: 0, currentInstallmentNumber: 0
    };
  }, [daysInPeriod, entries, settings, currentHourlyRate, currentPeriodId]);

  if (authLoading) return <div className="min-h-screen bg-slate-950 flex items-center justify-center"><Loader2 className="animate-spin text-emerald-500" /></div>;
  if (!user) return <Login />;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 pb-20 font-sans">
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30 px-4 h-14 flex items-center justify-between">
        <div className="flex items-center gap-2 bg-slate-800/50 p-1 pl-2 pr-3 rounded-full border border-slate-700">
            <User size={14} className="text-slate-400" />
            <span className="text-sm font-bold text-slate-200">{settings.userName}</span>
        </div>
        <div className="flex items-center gap-2">
           <button onClick={() => setIsVacationModalOpen(true)} className="p-1.5 text-slate-400 hover:text-purple-400"><Palmtree size={18} /></button>
           <button onClick={() => setIsSettingsOpen(true)} className="p-1.5 text-slate-400 hover:text-white"><SettingsIcon size={18} /></button>
           <button onClick={() => signOut(auth)} className="p-1.5 text-slate-500 hover:text-red-400"><LogOut size={18} /></button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-6">
        <PeriodSelector selectedDate={selectedDate} onDateChange={setSelectedDate} />

        <div ref={reportRef} className="space-y-6">
            <SummaryPanel 
                summary={periodSummary} settings={settings} dailyData={[]} 
                isPeriodPaid={isPeriodPaid} onTogglePaid={async () => {
                    const next = !isPeriodPaid;
                    const state = { id: currentPeriodId, isPaid: next, hourlyRate: currentHourlyRate };
                    setPeriodStates(prev => ({ ...prev, [currentPeriodId]: state }));
                    await db.savePeriodState(state);
                }} 
            />

            <div className="bg-slate-900 rounded-xl border border-slate-800 p-4 shadow-xl">
                <div className="grid grid-cols-7 gap-2">
                    {daysInPeriod.map(date => {
                        const dateStr = date.toISOString().split('T')[0];
                        const entry = getEntry(dateStr);
                        const progress = Math.min(100, (entry.hours / settings.dailyTargetHours) * 100);
                        return (
                            <button 
                                key={dateStr} onClick={() => setMobileSelectedDate(dateStr)}
                                className={`aspect-square rounded-lg border p-1 flex flex-col items-center justify-between transition-all active:scale-95 overflow-hidden ${
                                    entry.isHoliday ? 'border-yellow-500/30 bg-yellow-900/10' : 
                                    entry.isVacation ? 'border-purple-500/30 bg-purple-900/10' : 'border-slate-800 bg-slate-850 hover:bg-slate-800'
                                }`}
                            >
                                <span className="text-[10px] text-slate-500 font-bold">{date.getDate()}</span>
                                <div className="text-[9px] font-mono text-emerald-400 font-bold leading-none">
                                    {entry.hours > 0 ? `${entry.hours}h` : ''}
                                </div>
                                <div className="w-full h-1 bg-slate-700 rounded-full mt-1 overflow-hidden">
                                    <div className="h-full bg-emerald-500 transition-all" style={{ width: `${progress}%` }}></div>
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        </div>

        {mobileSelectedDate && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                <div className="bg-slate-900 w-full max-w-lg rounded-2xl border border-slate-700 flex flex-col max-h-[90vh]">
                    <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-850">
                        <div>
                            <h3 className="text-lg font-bold text-white capitalize">
                                {new Date(mobileSelectedDate + 'T12:00:00').toLocaleDateString('es-AR', { day: 'numeric', month: 'long', weekday: 'long' })}
                            </h3>
                            <div className="flex items-center gap-2 mt-1">
                                <div className="text-xs text-slate-400 flex items-center gap-1">
                                    Objetivo: <span className="text-blue-400 font-bold">{settings.dailyTargetHours}hs</span>
                                </div>
                                <div className="text-xs text-slate-400">
                                    Logrado: <span className="text-emerald-400 font-bold">{getEntry(mobileSelectedDate).hours}hs</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={() => setMobileSelectedDate(null)} className="p-2 bg-slate-800 rounded-full text-slate-400 hover:text-white"><X size={20} /></button>
                    </div>

                    <div className="p-6 overflow-y-auto space-y-6">
                        <div className="flex gap-2">
                             <button onClick={() => handleImmediateChange(mobileSelectedDate, 'isHoliday', !getEntry(mobileSelectedDate).isHoliday)} className={`flex-1 py-2 rounded-lg text-xs font-bold border ${getEntry(mobileSelectedDate).isHoliday ? 'bg-yellow-500/20 border-yellow-500 text-yellow-500' : 'border-slate-700 text-slate-500'}`}>FERIADO</button>
                             <button onClick={() => handleImmediateChange(mobileSelectedDate, 'isVacation', !getEntry(mobileSelectedDate).isVacation)} className={`flex-1 py-2 rounded-lg text-xs font-bold border ${getEntry(mobileSelectedDate).isVacation ? 'bg-purple-500/20 border-purple-500 text-purple-500' : 'border-slate-700 text-slate-500'}`}>VACACIONES</button>
                        </div>

                        <div className="space-y-4">
                            <div className="flex items-center justify-between border-b border-slate-800 pb-2">
                                <h4 className="text-xs font-bold text-slate-500 uppercase flex items-center gap-2"><Tag size={12} /> Desglose de Productos</h4>
                                <span className="text-xs font-bold text-emerald-400">{formatCurrency(getEntry(mobileSelectedDate).hours * currentHourlyRate)} acumulados</span>
                            </div>

                            <div className="space-y-2">
                                {(getEntry(mobileSelectedDate).tasks || []).map(task => (
                                    <div key={task.id} className="flex items-center justify-between bg-slate-950/50 p-3 rounded-lg border border-slate-800 group">
                                        <div className="flex flex-col">
                                            <span className="text-sm font-bold text-white flex items-center gap-2"><div className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></div> {task.code || 'S/C'}</span>
                                            <span className="text-[10px] text-slate-500">{task.minutes} min • {formatCurrency(task.profit)}</span>
                                        </div>
                                        <button onClick={() => handleTaskAction(mobileSelectedDate, 'remove', task.id)} className="p-2 text-slate-600 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"><Trash2 size={16} /></button>
                                    </div>
                                ))}

                                <button 
                                    onClick={() => {
                                        const code = prompt("Código del producto:");
                                        const min = parseInt(prompt("Minutos:") || "0");
                                        if (code && min > 0) handleTaskAction(mobileSelectedDate, 'add', undefined, { code, minutes: min });
                                    }}
                                    className="w-full py-3 border-2 border-dashed border-slate-800 rounded-xl text-slate-500 hover:border-emerald-500 hover:text-emerald-500 transition-all flex items-center justify-center gap-2"
                                >
                                    <Plus size={18} /> Añadir Producto/Tarea
                                </button>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase">Notas del Día</label>
                            <textarea 
                                value={getEntry(mobileSelectedDate).note}
                                onChange={(e) => handleImmediateChange(mobileSelectedDate, 'note', e.target.value)}
                                className="w-full bg-slate-950 border border-slate-700 rounded-xl p-3 text-sm text-slate-300 focus:border-emerald-500 outline-none"
                                placeholder="..." rows={3}
                            />
                        </div>
                    </div>
                </div>
            </div>
        )}
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={settings}
        currentPeriodRate={currentHourlyRate} currentPeriodId={currentPeriodId} onSave={async (ns, pr, pnr, ps) => {
            setSettings(ns); await db.saveSettings(ns);
            // Fix: using 'isPeriodPaid' instead of 'isPaid' to resolve shorthand property scope error.
            const state = { id: currentPeriodId, isPaid: isPeriodPaid, hourlyRate: pr, nonRemunerativePercent: pnr, seniorityPercentPerYear: ps };
            setPeriodStates(prev => ({ ...prev, [currentPeriodId]: state }));
            await db.savePeriodState(state);
        }}
      />
      <VacationModal isOpen={isVacationModalOpen} onClose={() => setIsVacationModalOpen(false)} onSave={async (s, e, iw) => {}} />
    </div>
  );
}

