        stats.totalHours += (entry.hours || 0);
        if (entry.isHoliday) { stats.hol += 8; stats.holAmt += (8 * rate); }
        if (entry.isVacation) { stats.vac += 8; stats.vacAmt += (8 * rate); }
      }
    });

    stats.totalAmount = (stats.totalHours * rate) + stats.holAmt + stats.vacAmt;

    return {
      totalHours: stats.totalHours, totalAmount: stats.totalAmount, holidayHours: stats.hol, holidayAmount: stats.holAmt,
      vacationHours: stats.vac, vacationAmount: stats.vacAmt, grandTotal: stats.totalAmount, appliedHourlyRate: rate,
