                                            <div className="p-3 border-l border-zinc-800 text-center font-mono text-xs text-zinc-400 flex items-center justify-center">
                                                {formatMinutesToHHMMSS(task.minutes)}
                                            </div>
                                            <div className="p-3 border-l border-zinc-800 text-right font-bold text-zinc-100 flex items-center justify-end px-4">
                                                {formatCurrency(task.profit)}
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Footer con acciones */}
                    <div className="p-4 bg-zinc-950 rounded-b-3xl border-t border-zinc-800 flex items-center justify-between gap-4">
