                        <div className="text-right">
                             <div className="text-[9px] font-bold text-zinc-500 uppercase">Total del Día</div>
                             <div className="text-xl font-black text-emerald-500 font-mono">{formatCurrency(getEntry(mobileSelectedDate).hours * currentHourlyRate)}</div>
                        </div>
                    </div>
                </div>
