      </main>

      {/* Floating Status Bar */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 no-print bg-zinc-900/80 backdrop-blur-xl border border-zinc-800 px-6 py-3 rounded-full shadow-2xl flex items-center gap-6 z-40">
