          </div>
      </div>

      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={settings}
        currentPeriodRate={currentHourlyRate} currentPeriodId={currentPeriodId} onSave={async (ns, pr) => {
