    const entry = getEntry(dateStr);
    let updatedTasks = [...(entry.tasks || [])];

    if (action === 'add' && taskData) {
        const newTask: DayTask = {
            id: Math.random().toString(36).substring(2, 11), // Robust fallback for ID
            code: taskData.code || '',
            minutes: taskData.minutes || 0,
            profit: ((taskData.minutes || 0) / 60) * currentHourlyRate,
            approved: false
        };
        updatedTasks.push(newTask);
    } else if (action === 'remove' && taskId) {
        updatedTasks = updatedTasks.filter(t => t.id !== taskId);
    } else if (action === 'toggle_approval' && taskId) {
        updatedTasks = updatedTasks.map(t => t.id === taskId ? { ...t, approved: !t.approved } : t);
    }

    const totalHours = updatedTasks.reduce((sum, t) => sum + (t.minutes / 60), 0);
    const updatedEntry: WorkDay = { ...entry, tasks: updatedTasks, hours: Math.round(totalHours * 100) / 100 };

    setEntries(prev => ({ ...prev, [dateStr]: updatedEntry }));
    await db.saveEntry(updatedEntry);
