                                          onChange={(e) => setNewTaskMinutes(e.target.value)}
                                          className="bg-zinc-950/50 border border-zinc-800 rounded px-2 py-1 text-center text-xs font-mono text-zinc-100 focus:ring-1 focus:ring-emerald-500 focus:border-emerald-500 outline-none w-16"
                                        />
                                    </div>
                                    <div className="p-2 border-l border-zinc-800 text-right font-bold text-emerald-500/50 flex items-center justify-end px-4 font-mono text-xs">
                                        {newTaskMinutes ? formatCurrency((parseInt(newTaskMinutes) || 0) / 60 * currentHourlyRate) : '$0'}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Footer con acciones */}
