          <div className="flex items-center gap-2 mb-4">
            <Sparkles size={18} className="text-emerald-500 animate-pulse" />
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-100">SUMMA AI COACH</h3>
          </div>

          <div className="flex-1 space-y-4">
            {!aiResponse ? (
              <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
                <div className="p-4 bg-zinc-950 rounded-2xl border border-zinc-800">
                   <p className="text-xs text-zinc-500 leading-relaxed">Analiza tu comportamiento mensual para obtener consejos personalizados.</p>
                </div>
                <button 
                  onClick={askAI}
                  disabled={aiLoading}
                  className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black text-xs uppercase rounded-2xl transition-all shadow-xl shadow-emerald-900/20 flex items-center justify-center gap-3 disabled:opacity-50"
                >
                  {aiLoading ? <Loader2 className="animate-spin" size={18} /> : <><BrainCircuit size={18} /> Consultar IA</>}
                </button>
              </div>
            ) : (
              <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-500">
