      {/* Metrics Row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Eficiencia', val: `${efficiency.toFixed(1)}%`, icon: <CheckCircle2 size={14} />, color: 'text-emerald-500' },
          { label: 'Promedio', val: `${avgHours.toFixed(1)} hs`, icon: <Clock size={14} />, color: 'text-zinc-100' },
          { label: 'Consistencia', val: efficiency > 90 ? 'Excelente' : 'Regular', icon: <TrendingUp size={14} />, color: efficiency > 90 ? 'text-emerald-500' : 'text-yellow-500' },
          { label: 'Días Activos', val: entries.filter(e => e.hours > 0).length, icon: <Calendar size={14} />, color: 'text-zinc-100' }
        ].map((m, i) => (
          <div key={i} className="bg-zinc-900 p-4 rounded-2xl border border-zinc-800 flex flex-col gap-1">
            <div className="flex items-center gap-2 text-zinc-500 text-[10px] font-black uppercase tracking-widest">
              {m.icon} {m.label}
