            </div>
            <div className="bg-zinc-900 rounded-3xl border border-zinc-800 p-6 shadow-2xl overflow-hidden">
                <div className="grid grid-cols-7 gap-px bg-zinc-800 mb-2 rounded-t-xl overflow-hidden">
                    {['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'].map(d => (
                        <div key={d} className="bg-zinc-950 p-2 text-center text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{d}</div>
                    ))}
                </div>
                <div className="grid grid-cols-7 gap-2">
                    {calendarDays.map((date, idx) => {
                        if (!date) return <div key={`empty-${idx}`} className="aspect-square bg-zinc-950/20 rounded-2xl border border-zinc-800/10"></div>;

                        const dateStr = date.toISOString().split('T')[0];
                        const entry = getEntry(dateStr);
                        const progress = Math.min(100, (entry.hours / settings.dailyTargetHours) * 100);
                        const isToday = new Date().toDateString() === date.toDateString();

                        return (
                            <button 
                                key={dateStr} onClick={() => setMobileSelectedDate(dateStr)}
                                className={`aspect-square rounded-2xl border p-2 flex flex-col items-center justify-between transition-all hover:border-emerald-500/50 active:scale-95 group ${
                                    isToday ? 'ring-2 ring-emerald-500/20 border-emerald-500/50 bg-emerald-500/5' : 'bg-zinc-950 border-zinc-800'
                                } ${
                                    entry.isHoliday ? 'bg-yellow-500/10 border-yellow-500/30' : 
                                    entry.isVacation ? 'bg-purple-500/10 border-purple-500/30' : ''
