                        <div className="p-4 flex items-center justify-center">$</div>
                    </div>

                    <div className="flex-1 overflow-y-auto bg-zinc-900 custom-scrollbar">
                        <div className="grid grid-cols-[100px_1fr] border-b border-zinc-800">
                            <div className="flex flex-col items-center justify-center border-r border-zinc-800 p-8 bg-zinc-950/30">
                                <span className="text-4xl font-black text-zinc-100 leading-none">{new Date(mobileSelectedDate + 'T12:00:00').getDate()}</span>
                                <span className="text-[10px] text-zinc-500 uppercase font-bold tracking-[0.2em] mt-2">{MONTHS[new Date(mobileSelectedDate + 'T12:00:00').getMonth()].slice(0,3)}</span>
                            </div>

                            <div className="flex flex-col divide-y divide-zinc-800 bg-zinc-900">
                                {(getEntry(mobileSelectedDate).tasks || []).map((task) => (
                                    <div key={task.id} className="grid grid-cols-[1fr_80px_100px_120px] hover:bg-zinc-800/50 transition-colors group">
