          { label: 'Promedio', val: `${avgHours.toFixed(1)} hs`, icon: <Clock size={14} />, color: 'text-zinc-100' },
          { label: 'Consistencia', val: efficiency > 90 ? 'Excelente' : 'Regular', icon: <TrendingUp size={14} />, color: efficiency > 90 ? 'text-emerald-500' : 'text-yellow-500' },
          { label: 'Días Activos', val: entries.filter(e => e.hours > 0).length, icon: <Calendar size={14} />, color: 'text-zinc-100' }
