import React, { useState, useEffect, useMemo, useRef } from 'react';
import { WorkDay, AppSettings, DEFAULT_SETTINGS, PeriodSummary, PeriodState, DayTask } from './types';
import { DAYS_OF_WEEK, MONTHS, formatCurrency } from './constants';
import { PeriodSelector } from './components/PeriodSelector';
import { SettingsModal } from './components/SettingsModal';
import { SummaryPanel } from './components/SummaryPanel';
import { VacationModal } from './components/VacationModal';
import { ProductivityInsights } from './components/ProductivityInsights';
import { Login } from './components/Login';
import { auth } from './firebase';
import { onAuthStateChanged, signOut, User as FirebaseUser } from 'firebase/auth';
import { Settings as SettingsIcon, Loader2, X, CheckCircle2, Palmtree, LogOut, Plus, Trash2, Tag, Check, Calendar, PlusCircle, List, LayoutGrid, Clock, Search, Filter, Group, BrainCircuit } from 'lucide-react';
import { db } from './db';

function App() {
  const [user, setUser] = useState<FirebaseUser | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [entries, setEntries] = useState<Record<string, WorkDay>>({});
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [periodStates, setPeriodStates] = useState<Record<string, PeriodState>>({});
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isVacationModalOpen, setIsVacationModalOpen] = useState(false);
  const [mobileSelectedDate, setMobileSelectedDate] = useState<string | null>(null);
  const [showInsights, setShowInsights] = useState(false);

  const [filterTerm, setFilterTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'subido' | 'pendiente'>('all');
  const [groupMode, setGroupMode] = useState<'none' | 'date' | 'code'>('none');

  const [newTaskCode, setNewTaskCode] = useState('');
  const [newTaskMinutes, setNewTaskMinutes] = useState('');

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (u) => { setUser(u); setAuthLoading(false); });
    return () => unsubscribe();
  }, []);

  // CARGA AUTOMÁTICA DE TRANSICIÓN (LIMPIA Y SIN DUPLICADOS)
  useEffect(() => {
    if (!user || authLoading) return;

    const loadAndCheckTransition = async () => {
      const [storedEntries, storedSettings, storedPeriodStates] = await Promise.all([
        db.getAllEntries(), db.getSettings(), db.getAllPeriodStates()
      ]);

      const currentSettings = storedSettings ? { ...DEFAULT_SETTINGS, ...storedSettings } : DEFAULT_SETTINGS;
      setSettings(currentSettings);
      setEntries(storedEntries || {});

      const statesMap: Record<string, PeriodState> = {};
      storedPeriodStates.forEach(ps => { statesMap[ps.id] = ps; });
      setPeriodStates(statesMap);

      // Solo si NO se ha importado antes
      if (!currentSettings.transitionFeb26Imported) {
        const rawData = [
          { code: "WKLO 108.118", mins: 75 }, { code: "WKLO 109.119", mins: 30 },
          { code: "WKLO 120", mins: 20 }, { code: "WKLO 121", mins: 5 },
          { code: "WKLO 122", mins: 45 }, { code: "WKLO 123", mins: 45 },
          { code: "WKLO 124", mins: 45 }, { code: "WKLO 130", mins: 20 },
          { code: "WKLO 131", mins: 6 }, { code: "WKLO 132", mins: 16 },
          { code: "WKLO 133", mins: 20 }, { code: "WKLO 134", mins: 10 },
          { code: "WKLO 140", mins: 15 }, { code: "WKLO 142", mins: 20 },
          { code: "WKLO 141", mins: 60 }, { code: "WKLO 144", mins: 25 },
          { code: "WKLO 145", mins: 25 }, { code: "WKLO 149", mins: 15 }
        ];

        const workDays = ['2026-02-02', '2026-02-03', '2026-02-04', '2026-02-05', '2026-02-06', '2026-02-09'];
        const rate = currentSettings.hourlyRate;
        const newEntries = { ...(storedEntries || {}) };

        let taskIdx = 0;
        for (let dayIdx = 0; dayIdx < workDays.length; dayIdx++) {
          const date = workDays[dayIdx];

          // REINICIO DEL DÍA: Para evitar duplicados si el proceso se cortó o repitió
          const entry: WorkDay = { 
            date, 
            hours: 0, 
            isAbsent: false, 
            isHoliday: false, 
            note: 'Carga de transición automática', 
            tasks: [] 
          };

          const tasksPerDay = 3; 
          for (let i = 0; i < tasksPerDay && taskIdx < rawData.length; i++) {
            const raw = rawData[taskIdx++];
            const newTask: DayTask = {
              id: `trans-${dayIdx}-${i}`, // ID determinista basado en posición para evitar duplicados en render
              code: `*${raw.code}`,
              minutes: raw.mins,
              profit: (raw.mins / 60) * rate,
              approved: true
            };
            entry.tasks.push(newTask);
          }

          const totalHours = entry.tasks.reduce((sum: number, t: DayTask) => sum + (t.minutes / 60), 0);
          entry.hours = Math.round(totalHours * 100) / 100;
          newEntries[date] = entry;
          await db.saveEntry(entry);
        }

        const updatedSettings = { ...currentSettings, transitionFeb26Imported: true };
        await db.saveSettings(updatedSettings);
        setSettings(updatedSettings);
        setEntries(newEntries);
        console.log("Transición de Feb 2026 cargada correctamente (limpia).");
      }
    };

    loadAndCheckTransition();
  }, [user, authLoading]);

  const currentPeriodId = useMemo(() => `${selectedDate.getFullYear()}-${String(selectedDate.getMonth() + 1).padStart(2, '0')}`, [selectedDate]);
  const isPeriodPaid = useMemo(() => periodStates[currentPeriodId]?.isPaid || false, [periodStates, currentPeriodId]);
  const currentHourlyRate = useMemo(() => periodStates[currentPeriodId]?.hourlyRate || settings.hourlyRate, [periodStates, currentPeriodId, settings.hourlyRate]);

  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDayOfMonth = new Date(year, month, 1).getDay();
    const lastDateOfMonth = new Date(year, month + 1, 0).getDate();

    const days: (Date | null)[] = Array(firstDayOfMonth).fill(null);
    for (let i = 1; i <= lastDateOfMonth; i++) {
      days.push(new Date(year, month, i));
    }
    return days;
  }, [selectedDate]);

  const getEntry = (dateStr: string): WorkDay => entries[dateStr] || {
    date: dateStr, hours: 0, isAbsent: false, isHoliday: false, isVacation: false,
    note: '', tasks: []
  };

  const currentMonthEntries = useMemo(() => {
    return (Object.values(entries) as WorkDay[]).filter(e => {
        const d = new Date(e.date + 'T12:00:00');
        return d.getMonth() === selectedDate.getMonth() && d.getFullYear() === selectedDate.getFullYear();
    });
  }, [entries, selectedDate]);

  const formatMinutesToHHMMSS = (totalMinutes: number) => {
    const h = Math.floor(totalMinutes / 60);
    const m = Math.floor(totalMinutes % 60);
    const s = Math.round((totalMinutes * 60) % 60);
    return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  };

  const processedMonthlyTasks = useMemo(() => {
    let list: { date: string, task: DayTask }[] = [];
    const sortedDates = Object.keys(entries).sort();

    sortedDates.forEach(dateStr => {
      const dateObj = new Date(dateStr + 'T12:00:00');
      if (dateObj.getMonth() === selectedDate.getMonth() && dateObj.getFullYear() === selectedDate.getFullYear()) {
        const entry = entries[dateStr];
        (entry.tasks || []).forEach(t => {
          const matchesTerm = t.code.toLowerCase().includes(filterTerm.toLowerCase());
          const matchesStatus = 
            filterStatus === 'all' || 
            (filterStatus === 'subido' && t.approved) || 
            (filterStatus === 'pendiente' && !t.approved);

          if (matchesTerm && matchesStatus) {
            list.push({ date: dateStr, task: t });
          }
        });
      }
    });

    if (groupMode === 'none') return { type: 'flat' as const, data: list };

    const grouped: Record<string, typeof list> = {};
    list.forEach(item => {
      const key = groupMode === 'date' ? item.date : item.task.code;
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(item);
    });

    return { type: 'grouped' as const, data: grouped };
  }, [entries, selectedDate, filterTerm, filterStatus, groupMode]);

  const handleTaskAction = async (dateStr: string, action: 'add' | 'remove' | 'toggle_approval' | 'update', taskId?: string, taskData?: Partial<DayTask>) => {
    const entry = getEntry(dateStr);
    let updatedTasks = [...(entry.tasks || [])];

    if (action === 'add' && taskData) {
        const newTask: DayTask = {
            id: Math.random().toString(36).substring(2, 11),
            code: taskData.code || '',
            minutes: taskData.minutes || 0,
            profit: ((taskData.minutes || 0) / 60) * currentHourlyRate,
            approved: false
        };
        updatedTasks.push(newTask);
    } else if (action === 'remove' && taskId) {
        updatedTasks = updatedTasks.filter(t => t.id !== taskId);
    } else if (action === 'toggle_approval' && taskId) {
        updatedTasks = updatedTasks.map(t => t.id === taskId ? { ...t, approved: !t.approved } : t);
    } else if (action === 'update' && taskId && taskData) {
        updatedTasks = updatedTasks.map(t => {
            if (t.id === taskId) {
                const updatedMinutes = taskData.minutes !== undefined ? taskData.minutes : t.minutes;
                return { 
                    ...t, 
                    ...taskData, 
                    profit: (updatedMinutes / 60) * currentHourlyRate 
                };
            }
            return t;
        });
    }

    const totalHours = updatedTasks.reduce((sum, t) => sum + (t.minutes / 60), 0);
    const updatedEntry: WorkDay = { ...entry, tasks: updatedTasks, hours: Math.round(totalHours * 100) / 100 };

    setEntries(prev => ({ ...prev, [dateStr]: updatedEntry }));
    await db.saveEntry(updatedEntry);
  };

  const handleAddNewTask = () => {
    if (!mobileSelectedDate || !newTaskCode || !newTaskMinutes) return;
    const mins = parseInt(newTaskMinutes);
    if (isNaN(mins) || mins <= 0) return;

    handleTaskAction(mobileSelectedDate, 'add', undefined, { 
      code: newTaskCode, 
      minutes: mins 
    });

    setNewTaskCode('');
    setNewTaskMinutes('');
  };

  const periodSummary = useMemo(() => {
    const rate = currentHourlyRate;
    let stats = { totalHours: 0, totalAmount: 0, holAmt: 0, vacAmt: 0 };

    calendarDays.forEach(d => {
      if (!d) return;
      const dateStr = d.toISOString().split('T')[0];
      const entry = entries[dateStr];
      if (entry) {
        stats.totalHours += (entry.hours || 0);
        if (entry.isHoliday) { stats.holAmt += (8 * rate); }
        if (entry.isVacation) { stats.vacAmt += (8 * rate); }
      }
    });

    stats.totalAmount = (stats.totalHours * rate) + stats.holAmt + stats.vacAmt;

    return {
      totalHours: stats.totalHours, totalAmount: stats.totalAmount, holidayHours: 0, holidayAmount: stats.holAmt,
      vacationHours: 0, vacationAmount: stats.vacAmt, grandTotal: stats.totalAmount, appliedHourlyRate: rate,
      advanceDeduction: 0, currentInstallmentNumber: 0
    };
  }, [calendarDays, entries, currentHourlyRate]);

  if (authLoading) return <div className="min-h-screen bg-zinc-950 flex items-center justify-center"><Loader2 className="animate-spin text-emerald-500" /></div>;
  if (!user) return <Login />;

  const renderTaskRow = (date: string, task: DayTask) => {
    const d = new Date(date + 'T12:00:00');
    return (
      <div key={task.id} className="grid grid-cols-[80px_1fr_100px_100px_120px] p-4 hover:bg-zinc-800/30 transition-colors group items-center">
          <div className="flex flex-col items-center justify-center">
              <span className="text-sm font-black text-zinc-100">{d.getDate()}</span>
              <span className="text-[8px] text-zinc-500 uppercase font-bold">{MONTHS[d.getMonth()].slice(0, 3)}</span>
          </div>
          <div className="pr-4">
              <input 
                  type="text"
                  value={task.code}
                  onChange={(e) => handleTaskAction(date, 'update', task.id, { code: e.target.value.toUpperCase() })}
                  className="bg-transparent border-none text-sm font-bold text-zinc-300 w-full focus:ring-1 focus:ring-emerald-500/50 rounded p-1 transition-all"
              />
          </div>
          <div className="flex items-center justify-center">
              <button 
                  onClick={() => handleTaskAction(date, 'toggle_approval', task.id)}
                  className={`w-5 h-5 rounded flex items-center justify-center shadow-inner transition-all ${task.approved ? 'bg-emerald-500 text-white' : 'bg-zinc-800 text-zinc-700 hover:text-zinc-500'}`}
              >
                  {task.approved && <Check size={12} strokeWidth={4} />}
              </button>
          </div>
          <div className="flex items-center justify-center px-4">
              <input 
                  type="number"
                  value={task.minutes}
                  onChange={(e) => handleTaskAction(date, 'update', task.id, { minutes: parseInt(e.target.value) || 0 })}
                  className="bg-zinc-950/50 border border-zinc-800 text-xs font-mono text-zinc-500 text-center w-20 py-1 rounded focus:ring-1 focus:ring-emerald-500/50 outline-none"
              />
          </div>
          <div className="text-sm font-mono font-black text-emerald-500 text-right">{formatCurrency(task.profit)}</div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-zinc-950 text-zinc-300 pb-32 font-sans selection:bg-emerald-500/30">
      <header className="bg-zinc-900/50 backdrop-blur-md border-b border-zinc-800 sticky top-0 z-30 px-6 h-16 flex items-center justify-between">
        <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-zinc-800 rounded-lg flex items-center justify-center border border-zinc-700 shadow-inner">
                <span className="text-emerald-500 font-black text-lg">S</span>
            </div>
            <span className="text-sm font-black text-zinc-100 uppercase tracking-tighter">SUMMA <span className="text-emerald-500">2.0</span></span>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => setShowInsights(!showInsights)} 
             className={`p-2 transition-colors ${showInsights ? 'text-emerald-500 bg-emerald-500/10 rounded-lg' : 'text-zinc-500 hover:text-emerald-500'}`}
             title="Productividad e IA"
           >
             <BrainCircuit size={18} />
           </button>
           <button onClick={() => setIsVacationModalOpen(true)} className="p-2 text-zinc-500 hover:text-emerald-500 transition-colors"><Palmtree size={18} /></button>
           <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-zinc-500 hover:text-emerald-500 transition-colors"><SettingsIcon size={18} /></button>
           <button onClick={() => signOut(auth)} className="p-2 text-zinc-600 hover:text-red-400 transition-colors"><LogOut size={18} /></button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8 space-y-12">
        <div className="space-y-6">
            <PeriodSelector selectedDate={selectedDate} onDateChange={setSelectedDate} />
            <SummaryPanel 
                summary={periodSummary} settings={settings} dailyData={[]} 
                isPeriodPaid={isPeriodPaid} onTogglePaid={async () => {
                    const next = !isPeriodPaid;
                    const state = { id: currentPeriodId, isPaid: next, hourlyRate: currentHourlyRate };
                    setPeriodStates(prev => ({ ...prev, [currentPeriodId]: state }));
                    await db.savePeriodState(state);
                }} 
            />
        </div>

        {showInsights && (
            <section className="animate-in slide-in-from-top-4 duration-500">
                <div className="flex items-center gap-2 mb-4">
                    <BrainCircuit size={18} className="text-emerald-500" />
                    <h2 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">Análisis de Productividad Meta 4h</h2>
                </div>
                <ProductivityInsights 
                  entries={currentMonthEntries} 
                  targetHours={settings.dailyTargetHours} 
                  currentHourlyRate={currentHourlyRate} 
                />
            </section>
        )}

        {/* Calendar Section */}
        <section className="space-y-4">
            <div className="flex items-center gap-2 mb-4">
                <LayoutGrid size={18} className="text-emerald-500" />
                <h2 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">Vista de Calendario</h2>
            </div>
            <div className="bg-zinc-900 rounded-3xl border border-zinc-800 p-6 shadow-2xl overflow-hidden">
                <div className="grid grid-cols-7 gap-px bg-zinc-800 mb-2 rounded-t-xl overflow-hidden">
                    {['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'].map(d => (
                        <div key={d} className="bg-zinc-950 p-2 text-center text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{d}</div>
                    ))}
                </div>
                <div className="grid grid-cols-7 gap-2">
                    {calendarDays.map((date, idx) => {
                        if (!date) return <div key={`empty-${idx}`} className="aspect-square bg-zinc-950/20 rounded-2xl border border-zinc-800/10"></div>;

                        const dateStr = date.toISOString().split('T')[0];
                        const entry = getEntry(dateStr);
                        const progress = Math.min(100, (entry.hours / settings.dailyTargetHours) * 100);
                        const isToday = new Date().toDateString() === date.toDateString();

                        return (
                            <button 
                                key={dateStr} onClick={() => setMobileSelectedDate(dateStr)}
                                className={`aspect-square rounded-2xl border p-2 flex flex-col items-center justify-between transition-all hover:border-emerald-500/50 active:scale-95 group ${
                                    isToday ? 'ring-2 ring-emerald-500/20 border-emerald-500/50 bg-emerald-500/5' : 'bg-zinc-950 border-zinc-800'
                                } ${
                                    entry.isHoliday ? 'bg-yellow-500/10 border-yellow-500/30' : 
                                    entry.isVacation ? 'bg-purple-500/10 border-purple-500/30' : ''
                                }`}
                            >
                                <span className={`text-[10px] font-black ${isToday ? 'text-emerald-500 underline underline-offset-4' : 'text-zinc-600'}`}>{date.getDate()}</span>
                                <div className="text-[10px] font-mono text-zinc-100 font-black">
                                    {entry.hours > 0 ? `${entry.hours}h` : ''}
                                </div>
                                <div className="w-full h-1 bg-zinc-800 rounded-full mt-1 overflow-hidden">
                                    <div className={`h-full shadow-[0_0_8px_rgba(16,185,129,0.5)] transition-all duration-700 ${entry.hours >= settings.dailyTargetHours ? 'bg-emerald-400' : 'bg-emerald-600'}`} style={{ width: `${progress}%` }}></div>
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        </section>

        {/* Monthly Cronological List */}
        <section className="space-y-4">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <List size={18} className="text-emerald-500" />
                    <h2 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">Lista Mensual de Trabajos</h2>
                </div>

                <div className="flex items-center gap-3 bg-zinc-900 border border-zinc-800 p-1 rounded-2xl shadow-lg no-print">
                    <div className="relative group">
                        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-600 group-focus-within:text-emerald-500 transition-colors" />
                        <input 
                            type="text" 
                            placeholder="Buscar código..." 
                            value={filterTerm}
                            onChange={(e) => setFilterTerm(e.target.value)}
                            className="bg-zinc-950 border border-zinc-800 rounded-xl py-1.5 pl-9 pr-3 text-xs text-zinc-300 focus:ring-1 focus:ring-emerald-500/30 outline-none w-40 placeholder:text-zinc-700"
                        />
                    </div>

                    <div className="h-6 w-px bg-zinc-800"></div>

                    <div className="flex items-center gap-1 bg-zinc-950 p-1 rounded-xl border border-zinc-800">
                        <button 
                            onClick={() => setFilterStatus('all')}
                            className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${filterStatus === 'all' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >TODOS</button>
                        <button 
                            onClick={() => setFilterStatus('subido')}
                            className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${filterStatus === 'subido' ? 'bg-emerald-500/20 text-emerald-500' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >SUBIDO</button>
                        <button 
                            onClick={() => setFilterStatus('pendiente')}
                            className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${filterStatus === 'pendiente' ? 'bg-yellow-500/20 text-yellow-500' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >PEND.</button>
                    </div>

                    <div className="h-6 w-px bg-zinc-800"></div>

                    <select 
                        value={groupMode}
                        onChange={(e) => setGroupMode(e.target.value as any)}
                        className="bg-zinc-950 border border-zinc-800 rounded-xl py-1.5 px-3 text-[10px] font-black text-zinc-400 uppercase tracking-widest outline-none focus:border-emerald-500/50 cursor-pointer"
                    >
                        <option value="none">Sin Agrupar</option>
                        <option value="date">Por Fecha</option>
                        <option value="code">Por Código</option>
                    </select>
                </div>
            </div>

            <div className="bg-zinc-900 rounded-3xl border border-zinc-800 shadow-2xl overflow-hidden">
                <div className="grid grid-cols-[80px_1fr_100px_100px_120px] bg-zinc-950 p-4 border-b border-zinc-800 text-[10px] font-black text-zinc-500 uppercase tracking-widest">
                    <div className="flex items-center justify-center">FECHA</div>
                    <div className="flex items-center">CÓDIGO</div>
                    <div className="flex items-center justify-center">SUBIDO</div>
                    <div className="flex items-center justify-center">TIEMPO (MIN)</div>
                    <div className="flex items-center justify-end">GANANCIA</div>
                </div>

                <div className="divide-y divide-zinc-800 max-h-[600px] overflow-y-auto custom-scrollbar bg-zinc-900/50">
                    {processedMonthlyTasks.type === 'flat' ? (
                        processedMonthlyTasks.data.length === 0 ? (
                            <div className="p-12 text-center text-zinc-600 italic text-sm">No se encontraron trabajos con estos filtros.</div>
                        ) : (
                            (processedMonthlyTasks.data as { date: string, task: DayTask }[]).map(({ date, task }) => renderTaskRow(date, task))
                        )
                    ) : (
                        Object.entries(processedMonthlyTasks.data).map(([key, items]) => {
                            const totalMinutes = items.reduce((s, i) => s + i.task.minutes, 0);
                            const totalProfit = items.reduce((s, i) => s + i.task.profit, 0);

                            return (
                                <div key={key} className="contents">
                                    <div className="bg-zinc-950/80 sticky top-0 z-10 p-3 px-6 flex items-center justify-between border-y border-zinc-800 backdrop-blur-sm">
                                        <div className="flex items-center gap-3">
                                            <div className="bg-emerald-500/10 text-emerald-500 p-1 rounded">
                                                {groupMode === 'date' ? <Calendar size={12} /> : <Tag size={12} />}
                                            </div>
                                            <span className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">
                                                {groupMode === 'date' ? `${key.split('-')[2]}/${key.split('-')[1]}/${key.split('-')[0]}` : key}
                                            </span>
                                        </div>
                                        <div className="flex gap-4 text-[10px] font-mono">
                                            <span className="text-zinc-500">{items.length} regs</span>
                                            <span className="text-zinc-300">{formatMinutesToHHMMSS(totalMinutes)}</span>
                                            <span className="text-emerald-500 font-black">{formatCurrency(totalProfit)}</span>
                                        </div>
                                    </div>
                                    {items.map(({ date, task }) => renderTaskRow(date, task))}
                                </div>
                            );
                        })
                    )}
                </div>

                <div className="bg-zinc-950 p-4 border-t border-zinc-800 flex justify-between items-center">
                    <span className="text-[10px] font-black text-zinc-500 uppercase">Resumen de Vista</span>
                    <div className="flex gap-6">
                        <div className="flex flex-col text-right">
                             <span className="text-[8px] font-bold text-zinc-600 uppercase">Total Items</span>
                             <span className="text-sm font-black text-zinc-100">
                                {processedMonthlyTasks.type === 'flat' 
                                    ? processedMonthlyTasks.data.length 
                                    : Object.values(processedMonthlyTasks.data).flat().length}
                             </span>
                        </div>
                        <div className="flex flex-col text-right">
                             <span className="text-[8px] font-bold text-zinc-600 uppercase">Subtot.</span>
                             <span className="text-sm font-black text-emerald-500">
                                {formatCurrency(
                                    processedMonthlyTasks.type === 'flat' 
                                    ? (processedMonthlyTasks.data as { date: string, task: DayTask }[]).reduce((s, t) => s + t.task.profit, 0)
                                    : Object.values(processedMonthlyTasks.data).flat().reduce((s, t) => s + (t as any).task.profit, 0)
                                )}
                             </span>
                        </div>
                    </div>
                </div>
            </div>
        </section>

        {mobileSelectedDate && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-xl p-4">
                <div className="bg-zinc-900 w-full max-w-2xl rounded-3xl border border-zinc-800 flex flex-col max-h-[90vh] shadow-[0_0_100px_rgba(0,0,0,0.8)] animate-in zoom-in-95 duration-200">
                    <div className="grid grid-cols-[100px_1fr_80px_100px_120px] bg-emerald-600 text-white font-black text-[10px] uppercase rounded-t-3xl overflow-hidden shadow-lg border-b border-emerald-700">
                        <div className="p-4 border-r border-emerald-500 flex items-center justify-center">FECHA</div>
                        <div className="p-4 border-r border-emerald-500 text-center">CÓDIGO</div>
                        <div className="p-4 border-r border-emerald-500 text-center">SUBIDO</div>
                        <div className="p-4 border-r border-emerald-500 text-center">MINUTOS</div>
                        <div className="p-4 flex items-center justify-center">$</div>
                    </div>

                    <div className="flex-1 overflow-y-auto bg-zinc-900 custom-scrollbar">
                        <div className="grid grid-cols-[100px_1fr] border-b border-zinc-800">
                            <div className="flex flex-col items-center justify-center border-r border-zinc-800 p-8 bg-zinc-950/30">
                                <span className="text-4xl font-black text-zinc-100 leading-none">{new Date(mobileSelectedDate + 'T12:00:00').getDate()}</span>
                                <span className="text-[10px] text-zinc-500 uppercase font-bold tracking-[0.2em] mt-2">{MONTHS[new Date(mobileSelectedDate + 'T12:00:00').getMonth()].slice(0,3)}</span>

                                {/* BLOQUE DE HORAS TOTALES DEL DÍA */}
                                <div className="mt-8 pt-6 border-t border-zinc-800/50 w-full flex flex-col items-center gap-1">
                                    <Clock size={14} className="text-emerald-500" />
                                    <span className="text-lg font-black text-zinc-100 font-mono tracking-tighter">
                                        {getEntry(mobileSelectedDate).hours.toFixed(2)}h
                                    </span>
                                    <span className="text-[8px] text-zinc-600 font-black uppercase tracking-[0.2em]">TIEMPO TOTAL</span>
                                </div>
                            </div>

                            <div className="flex flex-col divide-y divide-zinc-800 bg-zinc-900">
                                {(getEntry(mobileSelectedDate).tasks || []).map((task) => (
                                    <div key={task.id} className="grid grid-cols-[1fr_80px_100px_120px] hover:bg-zinc-800/50 transition-colors group">
                                        <div className="p-4 text-sm font-bold text-zinc-100 flex items-center gap-4">
                                            <button onClick={() => handleTaskAction(mobileSelectedDate, 'remove', task.id)} className="p-2 text-zinc-700 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 rounded-lg hover:bg-red-500/10"><Trash2 size={16} /></button>
                                            <input 
                                                type="text"
                                                value={task.code}
                                                onChange={(e) => handleTaskAction(mobileSelectedDate, 'update', task.id, { code: e.target.value.toUpperCase() })}
                                                className="bg-transparent border-none text-sm font-bold text-zinc-100 w-full focus:ring-1 focus:ring-emerald-500/50 rounded p-1 transition-all"
                                            />
                                        </div>
                                        <div className="p-4 border-l border-zinc-800 flex items-center justify-center">
                                            <button 
                                                onClick={() => handleTaskAction(mobileSelectedDate, 'toggle_approval', task.id)}
                                                className={`w-7 h-7 rounded-lg flex items-center justify-center transition-all shadow-lg ${task.approved ? 'bg-emerald-500 text-white' : 'bg-zinc-800 text-zinc-600 hover:bg-zinc-700'}`}
                                            >
                                                {task.approved && <Check size={16} strokeWidth={4} />}
                                            </button>
                                        </div>
                                        <div className="p-4 border-l border-zinc-800 flex items-center justify-center px-4">
                                            <input 
                                                type="number"
                                                value={task.minutes}
                                                onChange={(e) => handleTaskAction(mobileSelectedDate, 'update', task.id, { minutes: parseInt(e.target.value) || 0 })}
                                                className="bg-zinc-950 border border-zinc-800 text-center font-mono text-xs text-zinc-400 w-full py-1.5 rounded focus:ring-1 focus:ring-emerald-500/50 outline-none"
                                            />
                                        </div>
                                        <div className="p-4 border-l border-zinc-800 text-right font-black text-zinc-100 flex items-center justify-end px-4 font-mono">{formatCurrency(task.profit)}</div>
                                    </div>
                                ))}

                                <div className="grid grid-cols-[1fr_80px_100px_120px] bg-emerald-500/5 p-2">
                                    <div className="flex items-center gap-3 px-2">
                                        <Tag size={16} className="text-emerald-500" />
                                        <input 
                                          type="text" placeholder="NUEVO CÓDIGO" value={newTaskCode}
                                          onChange={(e) => setNewTaskCode(e.target.value.toUpperCase())}
                                          className="bg-transparent border-0 text-sm font-black text-zinc-100 focus:ring-0 placeholder:text-zinc-700 w-full tracking-wider"
                                        />
                                    </div>
                                    <div className="border-l border-zinc-800 flex items-center justify-center">
                                        <button 
                                          onClick={handleAddNewTask} disabled={!newTaskCode || !newTaskMinutes}
                                          className="w-10 h-10 rounded-xl bg-emerald-600 text-white flex items-center justify-center hover:scale-110 active:scale-95 transition-all disabled:opacity-30 shadow-lg shadow-emerald-500/20"
                                        >
                                          <Plus size={20} strokeWidth={3} />
                                        </button>
                                    </div>
                                    <div className="border-l border-zinc-800 flex items-center justify-center p-2">
                                        <input 
                                          type="number" placeholder="MIN" value={newTaskMinutes}
                                          onChange={(e) => setNewTaskMinutes(e.target.value)}
                                          className="bg-zinc-950 border border-zinc-800 rounded-lg px-2 py-2 text-center text-xs font-mono text-zinc-100 focus:ring-2 focus:ring-emerald-500 outline-none w-full"
                                        />
                                    </div>
                                    <div className="border-l border-zinc-800 text-right font-black text-emerald-500/30 flex items-center justify-end px-4 font-mono text-xs">
                                        {newTaskMinutes ? formatCurrency((parseInt(newTaskMinutes) || 0) / 60 * currentHourlyRate) : '$0'}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-6 bg-zinc-950 rounded-b-3xl border-t border-zinc-800 flex items-center justify-between shadow-2xl">
                        <button onClick={() => setMobileSelectedDate(null)} className="px-10 py-3 bg-zinc-900 hover:bg-zinc-800 text-zinc-500 hover:text-white font-black text-xs uppercase rounded-2xl transition-all tracking-widest border border-zinc-800">Cerrar</button>
                        <div className="text-right">
                             <div className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.3em] mb-1">Total del día</div>
                             <div className="text-3xl font-black text-emerald-500 font-mono tracking-tighter">{formatCurrency(getEntry(mobileSelectedDate).hours * currentHourlyRate)}</div>
                        </div>
                    </div>
                </div>
            </div>
        )}
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 no-print bg-zinc-900/90 backdrop-blur-3xl border border-zinc-800 px-10 py-5 rounded-[2.5rem] shadow-[0_30px_60px_rgba(0,0,0,0.8)] flex items-center gap-10 z-40 animate-in slide-in-from-bottom-8 duration-700">
          <div className="flex flex-col">
              <span className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.3em]">Tiempo Mensual</span>
              <span className="text-xl font-black text-zinc-100 font-mono">{periodSummary.totalHours.toFixed(2)} <span className="text-xs text-zinc-500">HS</span></span>
          </div>
          <div className="w-px h-10 bg-zinc-800"></div>
          <div className="flex flex-col">
              <span className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.3em]">Cierre Estimado</span>
              <span className="text-xl font-black text-emerald-500 font-mono tracking-tight">{formatCurrency(periodSummary.grandTotal)}</span>
          </div>
      </div>

      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={settings}
        currentPeriodRate={currentHourlyRate} currentPeriodId={currentPeriodId} 
        onSave={async (ns, pr) => {
            setSettings(ns); await db.saveSettings(ns);
            const state = { id: currentPeriodId, isPaid: isPeriodPaid, hourlyRate: pr };
            setPeriodStates(prev => ({ ...prev, [currentPeriodId]: state }));
            await db.savePeriodState(state);
        }}
      />
      <VacationModal isOpen={isVacationModalOpen} onClose={() => setIsVacationModalOpen(false)} onSave={async () => {}} />

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #27272a; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #3f3f46; }
      `}</style>
    </div>
  );
}

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { WorkDay, AppSettings, DEFAULT_SETTINGS, PeriodSummary, PeriodState, DayTask } from './types';
import { DAYS_OF_WEEK, MONTHS, formatCurrency } from './constants';
import { PeriodSelector } from './components/PeriodSelector';
import { SettingsModal } from './components/SettingsModal';
import { SummaryPanel } from './components/SummaryPanel';
import { VacationModal } from './components/VacationModal';
import { ProductivityInsights } from './components/ProductivityInsights';
import { Login } from './components/Login';
import { auth } from './firebase';
import { onAuthStateChanged, signOut, User as FirebaseUser } from 'firebase/auth';
import { Settings as SettingsIcon, Loader2, X, CheckCircle2, Palmtree, LogOut, Plus, Trash2, Tag, Check, Calendar, PlusCircle, List, LayoutGrid, Clock, Search, Filter, Group, BrainCircuit } from 'lucide-react';
import { db } from './db';

function App() {
  const [user, setUser] = useState<FirebaseUser | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [entries, setEntries] = useState<Record<string, WorkDay>>({});
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [periodStates, setPeriodStates] = useState<Record<string, PeriodState>>({});
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isVacationModalOpen, setIsVacationModalOpen] = useState(false);
  const [mobileSelectedDate, setMobileSelectedDate] = useState<string | null>(null);
  const [showInsights, setShowInsights] = useState(false);

  const [filterTerm, setFilterTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'subido' | 'pendiente'>('all');
  const [groupMode, setGroupMode] = useState<'none' | 'date' | 'code'>('none');

  const [newTaskCode, setNewTaskCode] = useState('');
  const [newTaskMinutes, setNewTaskMinutes] = useState('');

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (u) => { setUser(u); setAuthLoading(false); });
    return () => unsubscribe();
  }, []);

  // CARGA AUTOMÁTICA DE TRANSICIÓN (LIMPIA Y SIN DUPLICADOS)
  useEffect(() => {
    if (!user || authLoading) return;

    const loadAndCheckTransition = async () => {
      const [storedEntries, storedSettings, storedPeriodStates] = await Promise.all([
        db.getAllEntries(), db.getSettings(), db.getAllPeriodStates()
      ]);

      const currentSettings = storedSettings ? { ...DEFAULT_SETTINGS, ...storedSettings } : DEFAULT_SETTINGS;
      setSettings(currentSettings);
      setEntries(storedEntries || {});

      const statesMap: Record<string, PeriodState> = {};
      storedPeriodStates.forEach(ps => { statesMap[ps.id] = ps; });
      setPeriodStates(statesMap);

      // Solo si NO se ha importado antes
      if (!currentSettings.transitionFeb26Imported) {
        const rawData = [
          { code: "WKLO 108.118", mins: 75 }, { code: "WKLO 109.119", mins: 30 },
          { code: "WKLO 120", mins: 20 }, { code: "WKLO 121", mins: 5 },
          { code: "WKLO 122", mins: 45 }, { code: "WKLO 123", mins: 45 },
          { code: "WKLO 124", mins: 45 }, { code: "WKLO 130", mins: 20 },
          { code: "WKLO 131", mins: 6 }, { code: "WKLO 132", mins: 16 },
          { code: "WKLO 133", mins: 20 }, { code: "WKLO 134", mins: 10 },
          { code: "WKLO 140", mins: 15 }, { code: "WKLO 142", mins: 20 },
          { code: "WKLO 141", mins: 60 }, { code: "WKLO 144", mins: 25 },
          { code: "WKLO 145", mins: 25 }, { code: "WKLO 149", mins: 15 }
        ];

        const workDays = ['2026-02-02', '2026-02-03', '2026-02-04', '2026-02-05', '2026-02-06', '2026-02-09'];
        const rate = currentSettings.hourlyRate;
        const newEntries = { ...(storedEntries || {}) };

        let taskIdx = 0;
        for (let dayIdx = 0; dayIdx < workDays.length; dayIdx++) {
          const date = workDays[dayIdx];

          // REINICIO DEL DÍA: Para evitar duplicados si el proceso se cortó o repitió
          const entry: WorkDay = { 
            date, 
            hours: 0, 
            isAbsent: false, 
            isHoliday: false, 
            note: 'Carga de transición automática', 
            tasks: [] 
          };

          const tasksPerDay = 3; 
          for (let i = 0; i < tasksPerDay && taskIdx < rawData.length; i++) {
            const raw = rawData[taskIdx++];
            const newTask: DayTask = {
              id: `trans-${dayIdx}-${i}`, // ID determinista basado en posición para evitar duplicados en render
              code: `*${raw.code}`,
              minutes: raw.mins,
              profit: (raw.mins / 60) * rate,
              approved: true
            };
            entry.tasks.push(newTask);
          }

          const totalHours = entry.tasks.reduce((sum: number, t: DayTask) => sum + (t.minutes / 60), 0);
          entry.hours = Math.round(totalHours * 100) / 100;
          newEntries[date] = entry;
          await db.saveEntry(entry);
        }

        const updatedSettings = { ...currentSettings, transitionFeb26Imported: true };
        await db.saveSettings(updatedSettings);
        setSettings(updatedSettings);
        setEntries(newEntries);
        console.log("Transición de Feb 2026 cargada correctamente (limpia).");
      }
    };

    loadAndCheckTransition();
  }, [user, authLoading]);

  const currentPeriodId = useMemo(() => `${selectedDate.getFullYear()}-${String(selectedDate.getMonth() + 1).padStart(2, '0')}`, [selectedDate]);
  const isPeriodPaid = useMemo(() => periodStates[currentPeriodId]?.isPaid || false, [periodStates, currentPeriodId]);
  const currentHourlyRate = useMemo(() => periodStates[currentPeriodId]?.hourlyRate || settings.hourlyRate, [periodStates, currentPeriodId, settings.hourlyRate]);

  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDayOfMonth = new Date(year, month, 1).getDay();
    const lastDateOfMonth = new Date(year, month + 1, 0).getDate();

    const days: (Date | null)[] = Array(firstDayOfMonth).fill(null);
    for (let i = 1; i <= lastDateOfMonth; i++) {
      days.push(new Date(year, month, i));
    }
    return days;
  }, [selectedDate]);

  const getEntry = (dateStr: string): WorkDay => entries[dateStr] || {
    date: dateStr, hours: 0, isAbsent: false, isHoliday: false, isVacation: false,
    note: '', tasks: []
  };

  const currentMonthEntries = useMemo(() => {
    return (Object.values(entries) as WorkDay[]).filter(e => {
        const d = new Date(e.date + 'T12:00:00');
        return d.getMonth() === selectedDate.getMonth() && d.getFullYear() === selectedDate.getFullYear();
    });
  }, [entries, selectedDate]);

  const formatMinutesToHHMMSS = (totalMinutes: number) => {
    const h = Math.floor(totalMinutes / 60);
    const m = Math.floor(totalMinutes % 60);
    const s = Math.round((totalMinutes * 60) % 60);
    return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  };

  // FIX: Explicitly typing the useMemo result to ensure processedMonthlyTasks.data is correctly typed in JSX
  const processedMonthlyTasks = useMemo(() => {
    let list: { date: string, task: DayTask }[] = [];
    const sortedDates = Object.keys(entries).sort();

    sortedDates.forEach(dateStr => {
      const dateObj = new Date(dateStr + 'T12:00:00');
      if (dateObj.getMonth() === selectedDate.getMonth() && dateObj.getFullYear() === selectedDate.getFullYear()) {
        const entry = entries[dateStr];
        (entry.tasks || []).forEach(t => {
          const matchesTerm = t.code.toLowerCase().includes(filterTerm.toLowerCase());
          const matchesStatus = 
            filterStatus === 'all' || 
            (filterStatus === 'subido' && t.approved) || 
            (filterStatus === 'pendiente' && !t.approved);

          if (matchesTerm && matchesStatus) {
            list.push({ date: dateStr, task: t });
          }
        });
      }
    });

    if (groupMode === 'none') return { type: 'flat' as const, data: list };

    const grouped: Record<string, typeof list> = {};
    list.forEach(item => {
      const key = groupMode === 'date' ? item.date : item.task.code;
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(item);
    });

    return { type: 'grouped' as const, data: grouped };
  }, [entries, selectedDate, filterTerm, filterStatus, groupMode]) as { 
    type: 'flat'; 
    data: { date: string; task: DayTask }[]; 
  } | { 
    type: 'grouped'; 
    data: Record<string, { date: string; task: DayTask }[]>; 
  };

  const handleTaskAction = async (dateStr: string, action: 'add' | 'remove' | 'toggle_approval' | 'update', taskId?: string, taskData?: Partial<DayTask>) => {
    const entry = getEntry(dateStr);
    let updatedTasks = [...(entry.tasks || [])];

    if (action === 'add' && taskData) {
        const newTask: DayTask = {
            id: Math.random().toString(36).substring(2, 11),
            code: taskData.code || '',
            minutes: taskData.minutes || 0,
            profit: ((taskData.minutes || 0) / 60) * currentHourlyRate,
            approved: false
        };
        updatedTasks.push(newTask);
    } else if (action === 'remove' && taskId) {
        updatedTasks = updatedTasks.filter(t => t.id !== taskId);
    } else if (action === 'toggle_approval' && taskId) {
        updatedTasks = updatedTasks.map(t => t.id === taskId ? { ...t, approved: !t.approved } : t);
    } else if (action === 'update' && taskId && taskData) {
        updatedTasks = updatedTasks.map(t => {
            if (t.id === taskId) {
                const updatedMinutes = taskData.minutes !== undefined ? taskData.minutes : t.minutes;
                return { 
                    ...t, 
                    ...taskData, 
                    profit: (updatedMinutes / 60) * currentHourlyRate 
                };
            }
            return t;
        });
    }

    const totalHours = updatedTasks.reduce((sum, t) => sum + (t.minutes / 60), 0);
    const updatedEntry: WorkDay = { ...entry, tasks: updatedTasks, hours: Math.round(totalHours * 100) / 100 };

    setEntries(prev => ({ ...prev, [dateStr]: updatedEntry }));
    await db.saveEntry(updatedEntry);
  };

  const handleAddNewTask = () => {
    if (!mobileSelectedDate || !newTaskCode || !newTaskMinutes) return;
    const mins = parseInt(newTaskMinutes);
    if (isNaN(mins) || mins <= 0) return;

    handleTaskAction(mobileSelectedDate, 'add', undefined, { 
      code: newTaskCode, 
      minutes: mins 
    });

    setNewTaskCode('');
    setNewTaskMinutes('');
  };

  const periodSummary = useMemo(() => {
    const rate = currentHourlyRate;
    let stats = { totalHours: 0, totalAmount: 0, holAmt: 0, vacAmt: 0 };

    calendarDays.forEach(d => {
      if (!d) return;
      const dateStr = d.toISOString().split('T')[0];
      const entry = entries[dateStr];
      if (entry) {
        stats.totalHours += (entry.hours || 0);
        if (entry.isHoliday) { stats.holAmt += (8 * rate); }
        if (entry.isVacation) { stats.vacAmt += (8 * rate); }
      }
    });

    stats.totalAmount = (stats.totalHours * rate) + stats.holAmt + stats.vacAmt;

    return {
      totalHours: stats.totalHours, totalAmount: stats.totalAmount, holidayHours: 0, holidayAmount: stats.holAmt,
      vacationHours: 0, vacationAmount: stats.vacAmt, grandTotal: stats.totalAmount, appliedHourlyRate: rate,
      advanceDeduction: 0, currentInstallmentNumber: 0
    };
  }, [calendarDays, entries, currentHourlyRate]);

  if (authLoading) return <div className="min-h-screen bg-zinc-950 flex items-center justify-center"><Loader2 className="animate-spin text-emerald-500" /></div>;
  if (!user) return <Login />;

  const renderTaskRow = (date: string, task: DayTask) => {
    const d = new Date(date + 'T12:00:00');
    return (
      <div key={task.id} className="grid grid-cols-[80px_1fr_100px_100px_120px] p-4 hover:bg-zinc-800/30 transition-colors group items-center">
          <div className="flex flex-col items-center justify-center">
              <span className="text-sm font-black text-zinc-100">{d.getDate()}</span>
              <span className="text-[8px] text-zinc-500 uppercase font-bold">{MONTHS[d.getMonth()].slice(0, 3)}</span>
          </div>
          <div className="pr-4">
              <input 
                  type="text"
                  value={task.code}
                  onChange={(e) => handleTaskAction(date, 'update', task.id, { code: e.target.value.toUpperCase() })}
                  className="bg-transparent border-none text-sm font-bold text-zinc-300 w-full focus:ring-1 focus:ring-emerald-500/50 rounded p-1 transition-all"
              />
          </div>
          <div className="flex items-center justify-center">
              <button 
                  onClick={() => handleTaskAction(date, 'toggle_approval', task.id)}
                  className={`w-5 h-5 rounded flex items-center justify-center shadow-inner transition-all ${task.approved ? 'bg-emerald-500 text-white' : 'bg-zinc-800 text-zinc-700 hover:text-zinc-500'}`}
              >
                  {task.approved && <Check size={12} strokeWidth={4} />}
              </button>
          </div>
          <div className="flex items-center justify-center px-4">
              <input 
                  type="number"
                  value={task.minutes}
                  onChange={(e) => handleTaskAction(date, 'update', task.id, { minutes: parseInt(e.target.value) || 0 })}
                  className="bg-zinc-950/50 border border-zinc-800 text-xs font-mono text-zinc-500 text-center w-20 py-1 rounded focus:ring-1 focus:ring-emerald-500/50 outline-none"
              />
          </div>
          <div className="text-sm font-mono font-black text-emerald-500 text-right">{formatCurrency(task.profit)}</div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-zinc-950 text-zinc-300 pb-32 font-sans selection:bg-emerald-500/30">
      <header className="bg-zinc-900/50 backdrop-blur-md border-b border-zinc-800 sticky top-0 z-30 px-6 h-16 flex items-center justify-between">
        <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-zinc-800 rounded-lg flex items-center justify-center border border-zinc-700 shadow-inner">
                <span className="text-emerald-500 font-black text-lg">S</span>
            </div>
            <span className="text-sm font-black text-zinc-100 uppercase tracking-tighter">SUMMA <span className="text-emerald-500">2.0</span></span>
        </div>
        <div className="flex items-center gap-4">
           <button 
             onClick={() => setShowInsights(!showInsights)} 
             className={`p-2 transition-colors ${showInsights ? 'text-emerald-500 bg-emerald-500/10 rounded-lg' : 'text-zinc-500 hover:text-emerald-500'}`}
             title="Productividad e IA"
           >
             <BrainCircuit size={18} />
           </button>
           <button onClick={() => setIsVacationModalOpen(true)} className="p-2 text-zinc-500 hover:text-emerald-500 transition-colors"><Palmtree size={18} /></button>
           <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-zinc-500 hover:text-emerald-500 transition-colors"><SettingsIcon size={18} /></button>
           <button onClick={() => signOut(auth)} className="p-2 text-zinc-600 hover:text-red-400 transition-colors"><LogOut size={18} /></button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8 space-y-12">
        <div className="space-y-6">
            <PeriodSelector selectedDate={selectedDate} onDateChange={setSelectedDate} />
            <SummaryPanel 
                summary={periodSummary} settings={settings} dailyData={[]} 
                isPeriodPaid={isPeriodPaid} onTogglePaid={async () => {
                    const next = !isPeriodPaid;
                    const state = { id: currentPeriodId, isPaid: next, hourlyRate: currentHourlyRate };
                    setPeriodStates(prev => ({ ...prev, [currentPeriodId]: state }));
                    await db.savePeriodState(state);
                }} 
            />
        </div>

        {showInsights && (
            <section className="animate-in slide-in-from-top-4 duration-500">
                <div className="flex items-center gap-2 mb-4">
                    <BrainCircuit size={18} className="text-emerald-500" />
                    <h2 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">Análisis de Productividad Meta 4h</h2>
                </div>
                <ProductivityInsights 
                  entries={currentMonthEntries} 
                  targetHours={settings.dailyTargetHours} 
                  currentHourlyRate={currentHourlyRate} 
                />
            </section>
        )}

        {/* Calendar Section */}
        <section className="space-y-4">
            <div className="flex items-center gap-2 mb-4">
                <LayoutGrid size={18} className="text-emerald-500" />
                <h2 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">Vista de Calendario</h2>
            </div>
            <div className="bg-zinc-900 rounded-3xl border border-zinc-800 p-6 shadow-2xl overflow-hidden">
                <div className="grid grid-cols-7 gap-px bg-zinc-800 mb-2 rounded-t-xl overflow-hidden">
                    {['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'].map(d => (
                        <div key={d} className="bg-zinc-950 p-2 text-center text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{d}</div>
                    ))}
                </div>
                <div className="grid grid-cols-7 gap-2">
                    {calendarDays.map((date, idx) => {
                        if (!date) return <div key={`empty-${idx}`} className="aspect-square bg-zinc-950/20 rounded-2xl border border-zinc-800/10"></div>;

                        const dateStr = date.toISOString().split('T')[0];
                        const entry = getEntry(dateStr);
                        const progress = Math.min(100, (entry.hours / settings.dailyTargetHours) * 100);
                        const isToday = new Date().toDateString() === date.toDateString();

                        return (
                            <button 
                                key={dateStr} onClick={() => setMobileSelectedDate(dateStr)}
                                className={`aspect-square rounded-2xl border p-2 flex flex-col items-center justify-between transition-all hover:border-emerald-500/50 active:scale-95 group ${
                                    isToday ? 'ring-2 ring-emerald-500/20 border-emerald-500/50 bg-emerald-500/5' : 'bg-zinc-950 border-zinc-800'
                                } ${
                                    entry.isHoliday ? 'bg-yellow-500/10 border-yellow-500/30' : 
                                    entry.isVacation ? 'bg-purple-500/10 border-purple-500/30' : ''
                                }`}
                            >
                                <span className={`text-[10px] font-black ${isToday ? 'text-emerald-500 underline underline-offset-4' : 'text-zinc-600'}`}>{date.getDate()}</span>
                                <div className="text-[10px] font-mono text-zinc-100 font-black">
                                    {entry.hours > 0 ? `${entry.hours}h` : ''}
                                </div>
                                <div className="w-full h-1 bg-zinc-800 rounded-full mt-1 overflow-hidden">
                                    <div className={`h-full shadow-[0_0_8px_rgba(16,185,129,0.5)] transition-all duration-700 ${entry.hours >= settings.dailyTargetHours ? 'bg-emerald-400' : 'bg-emerald-600'}`} style={{ width: `${progress}%` }}></div>
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>
        </section>

        {/* Monthly Cronological List */}
        <section className="space-y-4">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <List size={18} className="text-emerald-500" />
                    <h2 className="text-xs font-black uppercase tracking-[0.2em] text-zinc-500">Lista Mensual de Trabajos</h2>
                </div>

                <div className="flex items-center gap-3 bg-zinc-900 border border-zinc-800 p-1 rounded-2xl shadow-lg no-print">
                    <div className="relative group">
                        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-600 group-focus-within:text-emerald-500 transition-colors" />
                        <input 
                            type="text" 
                            placeholder="Buscar código..." 
                            value={filterTerm}
                            onChange={(e) => setFilterTerm(e.target.value)}
                            className="bg-zinc-950 border border-zinc-800 rounded-xl py-1.5 pl-9 pr-3 text-xs text-zinc-300 focus:ring-1 focus:ring-emerald-500/30 outline-none w-40 placeholder:text-zinc-700"
                        />
                    </div>

                    <div className="h-6 w-px bg-zinc-800"></div>

                    <div className="flex items-center gap-1 bg-zinc-950 p-1 rounded-xl border border-zinc-800">
                        <button 
                            onClick={() => setFilterStatus('all')}
                            className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${filterStatus === 'all' ? 'bg-zinc-800 text-white shadow-inner' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >TODOS</button>
                        <button 
                            onClick={() => setFilterStatus('subido')}
                            className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${filterStatus === 'subido' ? 'bg-emerald-500/20 text-emerald-500' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >SUBIDO</button>
                        <button 
                            onClick={() => setFilterStatus('pendiente')}
                            className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${filterStatus === 'pendiente' ? 'bg-yellow-500/20 text-yellow-500' : 'text-zinc-600 hover:text-zinc-400'}`}
                        >PEND.</button>
                    </div>

                    <div className="h-6 w-px bg-zinc-800"></div>

                    <select 
                        value={groupMode}
                        onChange={(e) => setGroupMode(e.target.value as any)}
                        className="bg-zinc-950 border border-zinc-800 rounded-xl py-1.5 px-3 text-[10px] font-black text-zinc-400 uppercase tracking-widest outline-none focus:border-emerald-500/50 cursor-pointer"
                    >
                        <option value="none">Sin Agrupar</option>
                        <option value="date">Por Fecha</option>
                        <option value="code">Por Código</option>
                    </select>
                </div>
            </div>

            <div className="bg-zinc-900 rounded-3xl border border-zinc-800 shadow-2xl overflow-hidden">
                <div className="grid grid-cols-[80px_1fr_100px_100px_120px] bg-zinc-950 p-4 border-b border-zinc-800 text-[10px] font-black text-zinc-500 uppercase tracking-widest">
                    <div className="flex items-center justify-center">FECHA</div>
                    <div className="flex items-center">CÓDIGO</div>
                    <div className="flex items-center justify-center">SUBIDO</div>
                    <div className="flex items-center justify-center">TIEMPO (MIN)</div>
                    <div className="flex items-center justify-end">GANANCIA</div>
                </div>

                <div className="divide-y divide-zinc-800 max-h-[600px] overflow-y-auto custom-scrollbar bg-zinc-900/50">
                    {processedMonthlyTasks.type === 'flat' ? (
                        processedMonthlyTasks.data.length === 0 ? (
                            <div className="p-12 text-center text-zinc-600 italic text-sm">No se encontraron trabajos con estos filtros.</div>
                        ) : (
                            processedMonthlyTasks.data.map(({ date, task }) => renderTaskRow(date, task))
                        )
                    ) : (
                        Object.entries(processedMonthlyTasks.data).map(([key, items]) => {
                            // FIX: items is now properly typed as { date: string, task: DayTask }[] through explicit useMemo return typing
                            const totalMinutes = items.reduce((s, i) => s + i.task.minutes, 0);
                            const totalProfit = items.reduce((s, i) => s + i.task.profit, 0);

                            return (
                                <div key={key} className="contents">
                                    <div className="bg-zinc-950/80 sticky top-0 z-10 p-3 px-6 flex items-center justify-between border-y border-zinc-800 backdrop-blur-sm">
                                        <div className="flex items-center gap-3">
                                            <div className="bg-emerald-500/10 text-emerald-500 p-1 rounded">
                                                {groupMode === 'date' ? <Calendar size={12} /> : <Tag size={12} />}
                                            </div>
                                            <span className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">
                                                {groupMode === 'date' ? `${key.split('-')[2]}/${key.split('-')[1]}/${key.split('-')[0]}` : key}
                                            </span>
                                        </div>
                                        <div className="flex gap-4 text-[10px] font-mono">
                                            <span className="text-zinc-500">{items.length} regs</span>
                                            <span className="text-zinc-300">{formatMinutesToHHMMSS(totalMinutes)}</span>
                                            <span className="text-emerald-500 font-black">{formatCurrency(totalProfit)}</span>
                                        </div>
                                    </div>
                                    {items.map(({ date, task }) => renderTaskRow(date, task))}
                                </div>
                            );
                        })
                    )}
                </div>

                <div className="bg-zinc-950 p-4 border-t border-zinc-800 flex justify-between items-center">
                    <span className="text-[10px] font-black text-zinc-500 uppercase">Resumen de Vista</span>
                    <div className="flex gap-6">
                        <div className="flex flex-col text-right">
                             <span className="text-[8px] font-bold text-zinc-600 uppercase">Total Items</span>
                             <span className="text-sm font-black text-zinc-100">
                                {processedMonthlyTasks.type === 'flat' 
                                    ? processedMonthlyTasks.data.length 
                                    : Object.values(processedMonthlyTasks.data).flat().length}
                             </span>
                        </div>
                        <div className="flex flex-col text-right">
                             <span className="text-[8px] font-bold text-zinc-600 uppercase">Subtot.</span>
                             <span className="text-sm font-black text-emerald-500">
                                {formatCurrency(
                                    processedMonthlyTasks.type === 'flat' 
                                    ? processedMonthlyTasks.data.reduce((s, t) => s + t.task.profit, 0)
                                    : Object.values(processedMonthlyTasks.data).flat().reduce((s, t) => s + (t as any).task.profit, 0)
                                )}
                             </span>
                        </div>
                    </div>
                </div>
            </div>
        </section>

        {mobileSelectedDate && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-xl p-4">
                <div className="bg-zinc-900 w-full max-w-2xl rounded-3xl border border-zinc-800 flex flex-col max-h-[90vh] shadow-[0_0_100px_rgba(0,0,0,0.8)] animate-in zoom-in-95 duration-200">
                    <div className="grid grid-cols-[100px_1fr_80px_100px_120px] bg-emerald-600 text-white font-black text-[10px] uppercase rounded-t-3xl overflow-hidden shadow-lg border-b border-emerald-700">
                        <div className="p-4 border-r border-emerald-500 flex items-center justify-center">FECHA</div>
                        <div className="p-4 border-r border-emerald-500 text-center">CÓDIGO</div>
                        <div className="p-4 border-r border-emerald-500 text-center">SUBIDO</div>
                        <div className="p-4 border-r border-emerald-500 text-center">MINUTOS</div>
                        <div className="p-4 flex items-center justify-center">$</div>
                    </div>

                    <div className="flex-1 overflow-y-auto bg-zinc-900 custom-scrollbar">
                        <div className="grid grid-cols-[100px_1fr] border-b border-zinc-800">
                            <div className="flex flex-col items-center justify-center border-r border-zinc-800 p-8 bg-zinc-950/30">
                                <span className="text-4xl font-black text-zinc-100 leading-none">{new Date(mobileSelectedDate + 'T12:00:00').getDate()}</span>
                                <span className="text-[10px] text-zinc-500 uppercase font-bold tracking-[0.2em] mt-2">{MONTHS[new Date(mobileSelectedDate + 'T12:00:00').getMonth()].slice(0,3)}</span>

                                {/* BLOQUE DE HORAS TOTALES DEL DÍA */}
                                <div className="mt-8 pt-6 border-t border-zinc-800/50 w-full flex flex-col items-center gap-1">
                                    <Clock size={14} className="text-emerald-500" />
                                    <span className="text-lg font-black text-zinc-100 font-mono tracking-tighter">
                                        {getEntry(mobileSelectedDate).hours.toFixed(2)}h
                                    </span>
                                    <span className="text-[8px] text-zinc-600 font-black uppercase tracking-[0.2em]">TIEMPO TOTAL</span>
                                </div>
                            </div>

                            <div className="flex flex-col divide-y divide-zinc-800 bg-zinc-900">
                                {(getEntry(mobileSelectedDate).tasks || []).map((task) => (
                                    <div key={task.id} className="grid grid-cols-[1fr_80px_100px_120px] hover:bg-zinc-800/50 transition-colors group">
                                        <div className="p-4 text-sm font-bold text-zinc-100 flex items-center gap-4">
                                            <button onClick={() => handleTaskAction(mobileSelectedDate, 'remove', task.id)} className="p-2 text-zinc-700 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 rounded-lg hover:bg-red-500/10"><Trash2 size={16} /></button>
                                            <input 
                                                type="text"
                                                value={task.code}
                                                onChange={(e) => handleTaskAction(mobileSelectedDate, 'update', task.id, { code: e.target.value.toUpperCase() })}
                                                className="bg-transparent border-none text-sm font-bold text-zinc-100 w-full focus:ring-1 focus:ring-emerald-500/50 rounded p-1 transition-all"
                                            />
                                        </div>
                                        <div className="p-4 border-l border-zinc-800 flex items-center justify-center">
                                            <button 
                                                onClick={() => handleTaskAction(mobileSelectedDate, 'toggle_approval', task.id)}
                                                className={`w-7 h-7 rounded-lg flex items-center justify-center transition-all shadow-lg ${task.approved ? 'bg-emerald-500 text-white' : 'bg-zinc-800 text-zinc-600 hover:bg-zinc-700'}`}
                                            >
                                                {task.approved && <Check size={16} strokeWidth={4} />}
                                            </button>
                                        </div>
                                        <div className="p-4 border-l border-zinc-800 flex items-center justify-center px-4">
                                            <input 
                                                type="number"
                                                value={task.minutes}
                                                onChange={(e) => handleTaskAction(mobileSelectedDate, 'update', task.id, { minutes: parseInt(e.target.value) || 0 })}
                                                className="bg-zinc-950 border border-zinc-800 text-center font-mono text-xs text-zinc-400 w-full py-1.5 rounded focus:ring-1 focus:ring-emerald-500/50 outline-none"
                                            />
                                        </div>
                                        <div className="p-4 border-l border-zinc-800 text-right font-black text-zinc-100 flex items-center justify-end px-4 font-mono">{formatCurrency(task.profit)}</div>
                                    </div>
                                ))}

                                <div className="grid grid-cols-[1fr_80px_100px_120px] bg-emerald-500/5 p-2">
                                    <div className="flex items-center gap-3 px-2">
                                        <Tag size={16} className="text-emerald-500" />
                                        <input 
                                          type="text" placeholder="NUEVO CÓDIGO" value={newTaskCode}
                                          onChange={(e) => setNewTaskCode(e.target.value.toUpperCase())}
                                          className="bg-transparent border-0 text-sm font-black text-zinc-100 focus:ring-0 placeholder:text-zinc-700 w-full tracking-wider"
                                        />
                                    </div>
                                    <div className="border-l border-zinc-800 flex items-center justify-center">
                                        <button 
                                          onClick={handleAddNewTask} disabled={!newTaskCode || !newTaskMinutes}
                                          className="w-10 h-10 rounded-xl bg-emerald-600 text-white flex items-center justify-center hover:scale-110 active:scale-95 transition-all disabled:opacity-30 shadow-lg shadow-emerald-500/20"
                                        >
                                          <Plus size={20} strokeWidth={3} />
                                        </button>
                                    </div>
                                    <div className="border-l border-zinc-800 flex items-center justify-center p-2">
                                        <input 
                                          type="number" placeholder="MIN" value={newTaskMinutes}
                                          onChange={(e) => setNewTaskMinutes(e.target.value)}
                                          className="bg-zinc-950 border border-zinc-800 rounded-lg px-2 py-2 text-center text-xs font-mono text-zinc-100 focus:ring-2 focus:ring-emerald-500 outline-none w-full"
                                        />
                                    </div>
                                    <div className="border-l border-zinc-800 text-right font-black text-emerald-500/30 flex items-center justify-end px-4 font-mono text-xs">
                                        {newTaskMinutes ? formatCurrency((parseInt(newTaskMinutes) || 0) / 60 * currentHourlyRate) : '$0'}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-6 bg-zinc-950 rounded-b-3xl border-t border-zinc-800 flex items-center justify-between shadow-2xl">
                        <button onClick={() => setMobileSelectedDate(null)} className="px-10 py-3 bg-zinc-900 hover:bg-zinc-800 text-zinc-500 hover:text-white font-black text-xs uppercase rounded-2xl transition-all tracking-widest border border-zinc-800">Cerrar</button>
                        <div className="text-right">
                             <div className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.3em] mb-1">Total del día</div>
                             {/* FIX: Cast mobileSelectedDate as string since it's checked by truthiness in the conditional block above */}
                             <div className="text-3xl font-black text-emerald-500 font-mono tracking-tighter">{formatCurrency(getEntry(mobileSelectedDate as string).hours * currentHourlyRate)}</div>
                        </div>
                    </div>
                </div>
            </div>
        )}
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 no-print bg-zinc-900/90 backdrop-blur-3xl border border-zinc-800 px-10 py-5 rounded-[2.5rem] shadow-[0_30px_60px_rgba(0,0,0,0.8)] flex items-center gap-10 z-40 animate-in slide-in-from-bottom-8 duration-700">
          <div className="flex flex-col">
              <span className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.3em]">Tiempo Mensual</span>
              <span className="text-xl font-black text-zinc-100 font-mono">{periodSummary.totalHours.toFixed(2)} <span className="text-xs text-zinc-500">HS</span></span>
          </div>
          <div className="w-px h-10 bg-zinc-800"></div>
          <div className="flex flex-col">
              <span className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.3em]">Cierre Estimado</span>
              <span className="text-xl font-black text-emerald-500 font-mono tracking-tight">{formatCurrency(periodSummary.grandTotal)}</span>
          </div>
      </div>

      <SettingsModal 
        isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={settings}
        currentPeriodRate={currentHourlyRate} currentPeriodId={currentPeriodId} 
        onSave={async (ns, pr) => {
            setSettings(ns); await db.saveSettings(ns);
            const state = { id: currentPeriodId, isPaid: isPeriodPaid, hourlyRate: pr };
            setPeriodStates(prev => ({ ...prev, [currentPeriodId]: state }));
            await db.savePeriodState(state);
        }}
      />
      <VacationModal isOpen={isVacationModalOpen} onClose={() => setIsVacationModalOpen(false)} onSave={async () => {}} />

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #27272a; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #3f3f46; }
      `}</style>
    </div>
  );
}

export default App;
